{
  "name": "FloraVision AI - Smart Plant E-Commerce & AR Landscape",
  "description": "A cutting-edge plant e-commerce platform featuring AI disease detection and real-time AR landscape visualization using Gemini and device cameras.",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum PlantCategory {
  INDOOR = 'Indoor',
  OUTDOOR = 'Outdoor',
  TREE = 'Tree',
  SHRUB = 'Shrub'
}

export interface Plant {
  id: string;
  name: string;
  price: number;
  category: PlantCategory;
  size: string;
  sunlight: string;
  watering: string;
  soil: string;
  imageUrl: string;
  description: string;
}

export interface DiseaseAnalysis {
  species: string;
  diseaseName: string;
  severity: 'Low' | 'Moderate' | 'High';
  causes: string[];
  treatment: string;
  prevention: string;
}

export interface CartItem extends Plant {
  quantity: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DiseaseAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

export const analyzePlantDisease = async (base64Image: string): Promise<DiseaseAnalysis> => {
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: base64Image.split(',')[1] || base64Image,
            },
          },
          {
            text: "Analyze this plant image for diseases. Provide the species, disease name, severity, causes, treatment, and prevention in JSON format.",
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          species: { type: Type.STRING },
          diseaseName: { type: Type.STRING },
          severity: { type: Type.STRING, enum: ["Low", "Moderate", "High"] },
          causes: { type: Type.ARRAY, items: { type: Type.STRING } },
          treatment: { type: Type.STRING },
          prevention: { type: Type.STRING },
        },
        required: ["species", "diseaseName", "severity", "causes", "treatment", "prevention"],
      },
    },
  });

  return JSON.parse(response.text || "{}") as DiseaseAnalysis;
};

import React, { useRef, useEffect, useState, useCallback } from 'react';

interface CameraViewProps {
  onCapture?: (base64: string) => void;
  overlayContent?: React.ReactNode;
  isActive: boolean;
}

export const CameraView: React.FC<CameraViewProps> = ({ onCapture, overlayContent, isActive }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let stream: MediaStream | null = null;

    if (isActive) {
      const startCamera = async () => {
        try {
          stream = await navigator.mediaDevices.getUserMedia({ 
            video: { facingMode: 'environment' }, 
            audio: false 
          });
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
          }
        } catch (err) {
          setError("Could not access camera. Please check permissions.");
        }
      };
      startCamera();
    }

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [isActive]);

  const capture = useCallback(() => {
    if (videoRef.current && canvasRef.current && onCapture) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        onCapture(dataUrl);
      }
    }
  }, [onCapture]);

  if (error) return <div className="p-4 bg-red-100 text-red-700 rounded">{error}</div>;

  return (
    <div className="relative w-full aspect-video bg-black rounded-xl overflow-hidden shadow-2xl">
      <video
        ref={videoRef}
        autoPlay
        playsInline
        className="w-full h-full object-cover"
      />
      <canvas ref={canvasRef} className="hidden" />

      {overlayContent}

      {onCapture && (
        <button
          onClick={capture}
          className="absolute bottom-6 left-1/2 -translate-x-1/2 w-16 h-16 bg-white rounded-full border-4 border-emerald-500 shadow-xl active:scale-95 transition-transform flex items-center justify-center"
        >
          <div className="w-12 h-12 bg-emerald-500 rounded-full" />
        </button>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { CameraView } from './CameraView';
import { analyzePlantDisease } from '../services/geminiService';
import { DiseaseAnalysis } from '../types';

export const DiseaseScanner: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<DiseaseAnalysis | null>(null);

  const handleCapture = async (base64: string) => {
    setLoading(true);
    setResult(null);
    try {
      const analysis = await analyzePlantDisease(base64);
      setResult(analysis);
    } catch (error) {
      console.error(error);
      alert("Failed to analyze plant. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-4 space-y-8">
      <div className="text-center">
        <h2 className="text-3xl font-bold text-emerald-800">AI Plant Doctor</h2>
