      </div>

      <div className="grid md:grid-cols-2 gap-8">
        <div className="space-y-4">
          <CameraView isActive={true} onCapture={handleCapture} />
          <div className="text-center text-sm text-slate-500 italic">
            Tip: Keep the leaf in focus and well-lit.
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-lg min-h-[400px]">
          {loading ? (
            <div className="flex flex-col items-center justify-center h-full space-y-4">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-emerald-600" />
              <p className="text-emerald-700 font-medium">Gemini is analyzing your plant...</p>
            </div>
          ) : result ? (
            <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="text-xl font-bold text-slate-800">{result.species}</h3>
                  <p className="text-emerald-600 font-semibold">{result.diseaseName}</p>
                </div>
                <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                  result.severity === 'High' ? 'bg-red-100 text-red-700' :
                  result.severity === 'Moderate' ? 'bg-orange-100 text-orange-700' :
                  'bg-green-100 text-green-700'
                }`}>
                  {result.severity} Severity
                </span>
              </div>

              <div>
                <h4 className="font-semibold text-slate-700">Possible Causes:</h4>
                <ul className="list-disc list-inside text-slate-600 text-sm">
                  {result.causes.map((c, i) => <li key={i}>{c}</li>)}
                </ul>
              </div>

              <div className="p-4 bg-emerald-50 border border-emerald-100 rounded-lg">
                <h4 className="font-bold text-emerald-800 flex items-center gap-2">
                  <i className="fas fa-medkit" /> Treatment
                </h4>
                <p className="text-slate-700 text-sm mt-1">{result.treatment}</p>
              </div>

              <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg">
                <h4 className="font-bold text-blue-800 flex items-center gap-2">
                  <i className="fas fa-shield-alt" /> Prevention
                </h4>
                <p className="text-slate-700 text-sm mt-1">{result.prevention}</p>
              </div>

              <button 
                onClick={() => setResult(null)}
                className="w-full py-2 bg-slate-100 text-slate-600 rounded-lg hover:bg-slate-200 transition-colors"
              >
                Scan Another
              </button>
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-slate-400">
              <i className="fas fa-camera-retro text-5xl mb-4" />
              <p>Capture an image to see results here</p>
            </div>
