import React, { useState, useRef } from 'react';
import { CameraView } from './CameraView';
import { MOCK_PLANTS } from '../constants';
import { Plant } from '../types';

interface PlacedPlant extends Plant {
  x: number;
  y: number;
  scale: number;
  id_instance: number;
}

export const ARVisualizer: React.FC = () => {
  const [placedPlants, setPlacedPlants] = useState<PlacedPlant[]>([]);
  const [selectedPlant, setSelectedPlant] = useState<Plant>(MOCK_PLANTS[0]);
  const containerRef = useRef<HTMLDivElement>(null);

  const addPlantToScene = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newInstance: PlacedPlant = {
      ...selectedPlant,
      x,
      y,
      scale: 1,
      id_instance: Date.now(),
    };
    setPlacedPlants([...placedPlants, newInstance]);
  };

  const updatePlant = (id: number, delta: number) => {
    setPlacedPlants(prev => prev.map(p => 
      p.id_instance === id ? { ...p, scale: Math.max(0.2, p.scale + delta) } : p
    ));
  };

  const removePlant = (id: number) => {
    setPlacedPlants(prev => prev.filter(p => p.id_instance !== id));
  };

  return (
    <div className="max-w-6xl mx-auto p-4 space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-bold text-slate-800">AR Visualization</h2>
          <p className="text-slate-600">Place plants in your room using your camera feed.</p>
        </div>
        <div className="flex gap-2">
          {MOCK_PLANTS.map(p => (
            <button
              key={p.id}
              onClick={() => setSelectedPlant(p)}
              className={`w-12 h-12 rounded-lg border-2 overflow-hidden transition-all ${
                selectedPlant.id === p.id ? 'border-emerald-500 scale-110' : 'border-transparent opacity-60'
              }`}
            >
              <img src={p.imageUrl} alt={p.name} className="w-full h-full object-cover" />
            </button>
          ))}
        </div>
      </div>

      <div 
        ref={containerRef}
        onClick={addPlantToScene}
        className="relative overflow-hidden rounded-2xl cursor-crosshair"
      >
        <CameraView 
          isActive={true} 
          overlayContent={
            <div className="absolute inset-0 pointer-events-none">
              {placedPlants.map((p) => (
                <div
                  key={p.id_instance}
                  className="absolute pointer-events-auto group"
                  style={{
                    left: `${p.x}%`,
                    top: `${p.y}%`,
                    transform: `translate(-50%, -50%) scale(${p.scale})`,
                    zIndex: Math.floor(p.y),
                  }}
                >
                  <img 
                    src={p.imageUrl} 
                    alt={p.name} 
                    className="w-32 h-40 object-contain drop-shadow-2xl"
                  />
                  <div className="absolute -top-12 left-1/2 -translate-x-1/2 hidden group-hover:flex bg-black/80 text-white rounded-full p-1 gap-2 border border-white/20 px-3 py-1">
                    <button onClick={(e) => { e.stopPropagation(); updatePlant(p.id_instance, 0.1); }} className="hover:text-emerald-400">+</button>
                    <button onClick={(e) => { e.stopPropagation(); updatePlant(p.id_instance, -0.1); }} className="hover:text-emerald-400">-</button>
                    <button onClick={(e) => { e.stopPropagation(); removePlant(p.id_instance); }} className="hover:text-red-400">×</button>
                  </div>
                </div>
              ))}
            </div>
          }
        />
        <div className="absolute top-4 left-4 bg-emerald-600 text-white px-3 py-1 rounded-full text-xs font-bold animate-pulse">
          LIVE CAMERA FEED
        </div>
        <div className="absolute bottom-4 right-4 bg-white/20 backdrop-blur-md p-2 rounded-lg text-white text-xs">
          Click anywhere to place {selectedPlant.name}
        </div>
      </div>
    </div>
  );
};

