import React, { useState } from 'react';
import { MOCK_PLANTS } from './constants';
import { Plant, CartItem } from './types';
import { PlantCard } from './components/PlantCard';
import { ARVisualizer } from './components/ARVisualizer';
import { DiseaseScanner } from './components/DiseaseScanner';

type Tab = 'shop' | 'visualize' | 'doctor';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('shop');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  const addToCart = (plant: Plant) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === plant.id);
      if (existing) {
        return prev.map(item => item.id === plant.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...plant, quantity: 1 }];
    });
  };

  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);
  const totalPrice = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

  return (
    <div className="min-h-screen pb-24 lg:pb-0">
      {/* Desktop Sidebar / Mobile Bottom Nav */}
      <nav className="fixed bottom-0 left-0 right-0 z-50 bg-white border-t border-slate-200 lg:top-0 lg:bottom-0 lg:w-20 lg:border-r lg:border-t-0 flex lg:flex-col justify-around lg:justify-center items-center py-4 gap-8 glass-card">
        <button 
          onClick={() => setActiveTab('shop')}
          className={`flex flex-col items-center gap-1 lg:w-full transition-colors ${activeTab === 'shop' ? 'text-emerald-600' : 'text-slate-400'}`}
        >
          <i className="fas fa-store text-xl" />
          <span className="text-[10px] font-bold">SHOP</span>
        </button>
        <button 
          onClick={() => setActiveTab('visualize')}
          className={`flex flex-col items-center gap-1 lg:w-full transition-colors ${activeTab === 'visualize' ? 'text-emerald-600' : 'text-slate-400'}`}
        >
          <i className="fas fa-vr-cardboard text-xl" />
          <span className="text-[10px] font-bold">AR VIEW</span>
        </button>
        <button 
          onClick={() => setActiveTab('doctor')}
          className={`flex flex-col items-center gap-1 lg:w-full transition-colors ${activeTab === 'doctor' ? 'text-emerald-600' : 'text-slate-400'}`}
        >
          <i className="fas fa-stethoscope text-xl" />
          <span className="text-[10px] font-bold">DOCTOR</span>
        </button>
      </nav>

      {/* Main Content Area */}
      <main className="lg:ml-20 min-h-screen">
        <header className="px-6 py-6 flex justify-between items-center bg-white/50 backdrop-blur-md sticky top-0 z-40">
          <div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tighter">FLORAVISION <span className="text-emerald-500">AI</span></h1>
          </div>
          <button 
            onClick={() => setIsCartOpen(!isCartOpen)}
            className="relative p-3 bg-slate-100 rounded-full hover:bg-slate-200 transition-colors"
          >
            <i className="fas fa-shopping-bag text-slate-700" />
            {totalItems > 0 && (
              <span className="absolute -top-1 -right-1 bg-emerald-500 text-white text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
                {totalItems}
              </span>
            )}
          </button>
        </header>

        <div className="p-6">
          {activeTab === 'shop' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="bg-emerald-800 rounded-3xl p-8 text-white relative overflow-hidden shadow-2xl">
                <div className="relative z-10 max-w-lg space-y-4">
                  <h2 className="text-4xl font-bold leading-tight">Bring Nature to Your Living Room</h2>
                  <p className="opacity-80">Use our AI-powered AR tools to see how plants look in your space before you buy.</p>
                  <button onClick={() => setActiveTab('visualize')} className="bg-white text-emerald-800 px-6 py-2 rounded-full font-bold hover:bg-emerald-50 transition-colors">
                    Try AR Preview
                  </button>
                </div>
                <img 
                  src="https://picsum.photos/seed/hero/600/400" 
                  alt="Hero" 
                  className="absolute top-0 right-0 w-1/2 h-full object-cover opacity-30 mix-blend-overlay"
                />
              </div>

              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                {MOCK_PLANTS.map(plant => (
                  <PlantCard 
                    key={plant.id} 
                    plant={plant} 
                    onAddToCart={addToCart} 
                    onPreview={() => setActiveTab('visualize')}
                  />
                ))}
              </div>
            </div>
          )}

          {activeTab === 'visualize' && <ARVisualizer />}
          {activeTab === 'doctor' && <DiseaseScanner />}
        </div>
      </main>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[60] flex justify-end">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setIsCartOpen(false)} />
          <div className="relative w-full max-w-md bg-white h-full shadow-2xl p-6 flex flex-col animate-in slide-in-from-right duration-300">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-bold text-slate-800">Your Cart</h2>
              <button onClick={() => setIsCartOpen(false)}><i className="fas fa-times text-xl text-slate-400" /></button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-4 pr-2">
              {cart.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-slate-400 gap-4">
                  <i className="fas fa-shopping-basket text-5xl" />
                  <p>Your cart is empty</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="flex gap-4 p-3 bg-slate-50 rounded-xl border border-slate-100">
                    <img src={item.imageUrl} className="w-20 h-20 object-cover rounded-lg" />
                    <div className="flex-1 flex flex-col justify-between">
                      <div>
                        <h4 className="font-bold text-slate-800">{item.name}</h4>
                        <p className="text-sm text-slate-500">${item.price} × {item.quantity}</p>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="font-bold text-emerald-600">${(item.price * item.quantity).toFixed(2)}</span>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>

            {cart.length > 0 && (
              <div className="pt-6 border-t border-slate-100 space-y-4">
                <div className="flex justify-between text-lg font-bold">
                  <span>Total</span>
                  <span className="text-emerald-600">${totalPrice.toFixed(2)}</span>
                </div>
                <button className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold hover:bg-emerald-600 transition-colors shadow-lg shadow-emerald-200">
                  Proceed to Checkout
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

