import React, { useState } from 'react';
import { Plant, PlantCategory } from '../types';

interface AdminPanelProps {
  plants: Plant[];
  onAdd: (plant: Plant) => void;
  onRemove: (id: string) => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ plants, onAdd, onRemove }) => {
  const [formData, setFormData] = useState<Partial<Plant>>({
    category: PlantCategory.INDOOR,
    sunlight: 'Full Sun',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newPlant = {
      ...formData,
      id: Date.now().toString(),
    } as Plant;
    onAdd(newPlant);
    alert('Plant added successfully!');
  };

  return (
    <div className="max-w-5xl mx-auto p-6 space-y-8">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
        <h2 className="text-2xl font-bold text-slate-800 mb-6">Add New Plant</h2>
        <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <input required placeholder="Plant Name" className="p-3 bg-slate-50 rounded-lg border" onChange={e => setFormData({...formData, name: e.target.value})} />
