import React, { useState, useRef, useEffect } from 'react';
import { CameraView } from './CameraView';
import { MOCK_PLANTS, GARDEN_TOOLS } from '../constants';
import { LandscapeItem, Plant, Tool } from '../types';

export const LandscapeDesigner: React.FC = () => {
  const [items, setItems] = useState<LandscapeItem[]>([]);
  const [selectedItemId, setSelectedItemId] = useState<string>(MOCK_PLANTS[0].id);
  const [mode, setMode] = useState<'plant' | 'tool'>('plant');
  const [location, setLocation] = useState<{lat: number, lng: number} | null>(null);
  const [locationInfo, setLocationInfo] = useState<string>('Detecting location for suitability...');

  useEffect(() => {
    navigator.geolocation.getCurrentPosition(
      (pos) => setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => setLocationInfo('Location access denied. Using generic suitability.')
    );
  }, []);

  const addItem = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newItem: LandscapeItem = {
      instanceId: Math.random().toString(36).substr(2, 9),
      itemId: selectedItemId,
      type: mode,
      x, y, rotation: 0, scale: 1
    };
    setItems([...items, newItem]);
  };

  const removeItem = (id: string) => setItems(items.filter(i => i.instanceId !== id));

  const getItemData = (item: LandscapeItem) => {
    if (item.type === 'plant') return MOCK_PLANTS.find(p => p.id === item.itemId);
    return GARDEN_TOOLS.find(t => t.id === item.itemId);
  };

  return (
    <div className="max-w-6xl mx-auto p-4 space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800">Landscape Designer</h2>
          <p className="text-slate-600">Drag tools and plants to design your perfect garden.</p>
          <div className="mt-2 text-xs font-bold text-emerald-700 bg-emerald-50 px-3 py-1 rounded-full inline-block">
            <i className="fas fa-map-marker-alt mr-2" />
            {location ? `Suitability: Zone detected near ${location.lat.toFixed(2)}` : locationInfo}
          </div>
        </div>

        <div className="flex bg-slate-100 p-1 rounded-xl">
          <button 
            onClick={() => { setMode('plant'); setSelectedItemId(MOCK_PLANTS[0].id); }}
            className={`px-4 py-2 rounded-lg font-bold text-sm transition-all ${mode === 'plant' ? 'bg-white shadow-sm text-emerald-600' : 'text-slate-500'}`}
          >
            Plants
          </button>
          <button 
            onClick={() => { setMode('tool'); setSelectedItemId(GARDEN_TOOLS[0].id); }}
            className={`px-4 py-2 rounded-lg font-bold text-sm transition-all ${mode === 'tool' ? 'bg-white shadow-sm text-emerald-600' : 'text-slate-500'}`}
          >
            Tools
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-1 space-y-4">
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="font-bold text-slate-800 mb-4">Assets</h3>
            <div className="grid grid-cols-2 gap-2">
              {(mode === 'plant' ? MOCK_PLANTS : GARDEN_TOOLS).map((item: any) => (
                <button
                  key={item.id}
                  onClick={() => setSelectedItemId(item.id)}
                  className={`p-2 rounded-xl border-2 transition-all flex flex-col items-center gap-1 ${
                    selectedItemId === item.id ? 'border-emerald-500 bg-emerald-50' : 'border-transparent bg-slate-50'
                  }`}
                >
                  <img src={item.imageUrl} className="w-12 h-12 object-contain" />
                  <span className="text-[10px] font-bold text-center line-clamp-1">{item.name}</span>
                </button>
              ))}
            </div>
          </div>

          {mode === 'plant' && (
            <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100">
              <h4 className="text-xs font-bold text-blue-800 mb-2 uppercase">Placement Tip</h4>
              <p className="text-[11px] text-blue-700">
                {MOCK_PLANTS.find(p => p.id === selectedItemId)?.sunlight === 'Full Sun' 
                  ? "Place this in the brightest area of your camera feed for best growth."
                  : "This plant prefers shaded corners or indoor placement."}
              </p>
            </div>
          )}
        </div>

        <div className="lg:col-span-3">
          <div 
            onClick={addItem}
            className="relative rounded-3xl overflow-hidden cursor-copy shadow-2xl border-4 border-white"
          >
            <CameraView 
              isActive={true} 
              overlayContent={
                <div className="absolute inset-0 pointer-events-none">
                  {items.map((item) => {
                    const data = getItemData(item);
                    return (
                      <div
                        key={item.instanceId}
                        className="absolute pointer-events-auto group"
                        style={{
                          left: `${item.x}%`,
                          top: `${item.y}%`,
                          transform: `translate(-50%, -50%)`,
                          zIndex: Math.floor(item.y)
                        }}
                      >
                        <img 
                          src={data?.imageUrl} 
                          className={`${item.type === 'plant' ? 'w-24 h-32' : 'w-16 h-16'} object-contain drop-shadow-xl`}
                        />
                        <button 
                          onClick={(e) => { e.stopPropagation(); removeItem(item.instanceId); }}
                          className="absolute -top-2 -right-2 bg-red-500 text-white w-6 h-6 rounded-full opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-xs"
                        >
                          ×
                        </button>
                      </div>
                    );
                  })}
                </div>
              }
            />
            <div className="absolute bottom-4 left-4 bg-black/60 backdrop-blur-md text-white px-4 py-2 rounded-2xl text-xs">
              Designing Layout: Click to place {mode}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MOCK_PLANTS } from './constants';
import { Plant, CartItem } from './types';
import { PlantCard } from './components/PlantCard';
