type Tab = 'shop' | 'visualize' | 'doctor' | 'admin' | 'landscape';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('shop');
  const [plants, setPlants] = useState<Plant[]>(MOCK_PLANTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  const addToCart = (plant: Plant) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === plant.id);
      if (existing) {
        return prev.map(item => item.id === plant.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...plant, quantity: 1 }];
    });
  };

  const addPlant = (plant: Plant) => setPlants([...plants, plant]);
  const removePlant = (id: string) => setPlants(plants.filter(p => p.id !== id));

  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);
  const totalPrice = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

  return (
    <div className="min-h-screen pb-24 lg:pb-0">
      <nav className="fixed bottom-0 left-0 right-0 z-50 bg-white border-t border-slate-200 lg:top-0 lg:bottom-0 lg:w-20 lg:border-r lg:border-t-0 flex lg:flex-col justify-around lg:justify-center items-center py-4 gap-8 glass-card">
        <button onClick={() => setActiveTab('shop')} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'shop' ? 'text-emerald-600' : 'text-slate-400'}`}>
          <i className="fas fa-store text-xl" />
          <span className="text-[8px] font-bold">SHOP</span>
        </button>
        <button onClick={() => setActiveTab('landscape')} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'landscape' ? 'text-emerald-600' : 'text-slate-400'}`}>
          <i className="fas fa-drafting-compass text-xl" />
          <span className="text-[8px] font-bold">DESIGN</span>
        </button>
        <button onClick={() => setActiveTab('visualize')} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'visualize' ? 'text-emerald-600' : 'text-slate-400'}`}>
          <i className="fas fa-vr-cardboard text-xl" />
          <span className="text-[8px] font-bold">AR</span>
        </button>
        <button onClick={() => setActiveTab('doctor')} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'doctor' ? 'text-emerald-600' : 'text-slate-400'}`}>
          <i className="fas fa-stethoscope text-xl" />
          <span className="text-[8px] font-bold">DOC</span>
        </button>
        <button onClick={() => setActiveTab('admin')} className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'admin' ? 'text-emerald-600' : 'text-slate-400'}`}>
          <i className="fas fa-user-shield text-xl" />
          <span className="text-[8px] font-bold">ADMIN</span>
        </button>
      </nav>

      <main className="lg:ml-20 min-h-screen">
        <header className="px-6 py-6 flex justify-between items-center bg-white/50 backdrop-blur-md sticky top-0 z-40">
          <h1 className="text-2xl font-black text-slate-800 tracking-tighter">FLORAVISION <span className="text-emerald-500">AI</span></h1>
          <button onClick={() => setIsCartOpen(!isCartOpen)} className="relative p-3 bg-slate-100 rounded-full">
            <i className="fas fa-shopping-bag text-slate-700" />
            {totalItems > 0 && <span className="absolute -top-1 -right-1 bg-emerald-500 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">{totalItems}</span>}
          </button>
        </header>

        <div className="p-6">
          {activeTab === 'shop' && (
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6 animate-in fade-in duration-500">
              {plants.map(plant => (
                <PlantCard key={plant.id} plant={plant} onAddToCart={addToCart} onPreview={() => setActiveTab('visualize')} />
              ))}
            </div>
          )}
          {activeTab === 'landscape' && <LandscapeDesigner />}
          {activeTab === 'visualize' && <ARVisualizer />}
          {activeTab === 'doctor' && <DiseaseScanner />}
          {activeTab === 'admin' && <AdminPanel plants={plants} onAdd={addPlant} onRemove={removePlant} />}
        </div>
      </main>

      {/* Cart Drawer Logic Remains Same */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[60] flex justify-end">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setIsCartOpen(false)} />
          <div className="relative w-full max-w-md bg-white h-full shadow-2xl p-6 flex flex-col animate-in slide-in-from-right duration-300">
            <h2 className="text-2xl font-bold mb-8">Your Cart</h2>
            <div className="flex-1 overflow-y-auto space-y-4">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-3 bg-slate-50 rounded-xl border">
                  <img src={item.imageUrl} className="w-16 h-16 object-cover rounded-lg" />
                  <div>
                    <h4 className="font-bold">{item.name}</h4>
                    <p className="text-sm text-slate-500">${item.price} × {item.quantity}</p>
                  </div>
                </div>
              ))}
            </div>
            <div className="pt-6 border-t mt-4">
              <div className="flex justify-between font-bold mb-4"><span>Total</span><span>${totalPrice.toFixed(2)}</span></div>
              <button className="w-full bg-emerald-600 text-white py-4 rounded-xl font-bold">Checkout</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

