import { GoogleGenAI, Type } from "@google/genai";
import { DiseaseAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

export const analyzePlantDisease = async (base64Image: string): Promise<DiseaseAnalysis> => {
  // Use gemini-3-flash-preview for basic text/image tasks
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              // Extract base64 data without prefix
              data: base64Image.split(',')[1] || base64Image,
            },
          },
          {
            text: "Analyze this plant image for diseases. Provide the species, disease name, severity, causes, treatment, and prevention in JSON format.",
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          species: { type: Type.STRING },
          diseaseName: { type: Type.STRING },
          severity: { type: Type.STRING },
          causes: { type: Type.ARRAY, items: { type: Type.STRING } },
          treatment: { type: Type.STRING },
          prevention: { type: Type.STRING },
        },
        required: ["species", "diseaseName", "severity", "causes", "treatment", "prevention"],
      },
    },
  });

  // Accessing response.text directly as a property
  const jsonStr = response.text?.trim() || "{}";
  return JSON.parse(jsonStr) as DiseaseAnalysis;
};

