export const LandscapeDesigner: React.FC = () => {
  const [items, setItems] = useState<LandscapeItem[]>([]);
  const [selectedItemId, setSelectedItemId] = useState<string>(MOCK_PLANTS[0].id);
  const [mode, setMode] = useState<'plant' | 'tool'>('plant');
  const [location, setLocation] = useState<{lat: number, lng: number} | null>(null);

  useEffect(() => {
    navigator.geolocation.getCurrentPosition(
      (pos) => setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      (err) => console.log('Loc error', err)
    );
  }, []);

  const aiSuggestions = useMemo(() => {
    const itemCount = items.length;
    if (itemCount === 0) return "Select a plant to start your landscape journey.";
    if (itemCount < 3) return "Try adding some lighting or seating artifacts to balance the greenery.";
    if (itemCount >= 3 && itemCount < 6) return "Great layering! Consider adding a stone fountain as a focal point.";
    return "This landscape looks professional. Check lighting distribution for night-time aesthetics.";
  }, [items]);

  const addItem = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newItem: LandscapeItem = {
      instanceId: Math.random().toString(36).substr(2, 9),
      itemId: selectedItemId,
      type: mode,
      x, y, rotation: 0, scale: 1
    };
    setItems([...items, newItem]);
  };

  const removeItem = (id: string) => setItems(items.filter(i => i.instanceId !== id));

  const getItemData = (item: LandscapeItem) => {
    if (item.type === 'plant') return MOCK_PLANTS.find(p => p.id === item.itemId);
    return GARDEN_TOOLS.find(t => t.id === item.itemId);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-4 px-4">
      <div className="relative h-[75vh] rounded-[3rem] overflow-hidden border-[12px] border-white shadow-2xl bg-slate-200">
        <div 
          onClick={addItem}
          className="w-full h-full relative cursor-crosshair group"
        >
          <CameraView 
            isActive={true} 
            overlayContent={
              <div className="absolute inset-0 pointer-events-none">
                {items.map((item) => {
                  const data = getItemData(item);
                  return (
                    <div
                      key={item.instanceId}
                      className="absolute pointer-events-auto group/item animate-in zoom-in-50 duration-500"
                      style={{
                        left: `${item.x}%`,
                        top: `${item.y}%`,
                        transform: `translate(-50%, -100%) scale(${item.scale})`,
                        zIndex: Math.floor(item.y)
                      }}
                    >
                      {/* Background removal simulation via masking/multiply for better blending with reality */}
                      <div className="relative">
                        <img 
                          src={data?.imageUrl} 
                          className={`${item.type === 'plant' ? 'w-48 h-64' : 'w-24 h-24'} object-contain transition-all duration-300 drop-shadow-[0_30px_30px_rgba(0,0,0,0.6)]`}
                          style={{ 
                            filter: 'contrast(1.1) saturate(1.2) brightness(1.0)',
                            // Simulate cutout behavior
                            maskImage: 'radial-gradient(circle, black 80%, transparent 100%)',
                            WebkitMaskImage: 'radial-gradient(circle, black 80%, transparent 100%)'
                          }}
                        />
                        <div className="absolute inset-0 bg-black/5 mix-blend-multiply opacity-50 rounded-full blur-xl translate-y-1/2 scale-x-110 pointer-events-none" />
                      </div>

                      <div className="absolute -top-12 left-1/2 -translate-x-1/2 opacity-0 group-hover/item:opacity-100 flex gap-2 bg-white/90 backdrop-blur-md p-2 rounded-2xl shadow-xl transition-all border border-slate-100 scale-90">
                        <button 
                           onClick={(e) => { e.stopPropagation(); removeItem(item.instanceId); }}
                           className="bg-red-500 text-white w-8 h-8 rounded-xl flex items-center justify-center shadow-lg hover:scale-110 transition-transform"
                        >
                          <i className="fas fa-trash text-xs" />
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            }
          />
        </div>

        {/* Dynamic AI Suggestion Bar */}
        <div className="absolute top-8 left-1/2 -translate-x-1/2 w-[90%] md:w-auto min-w-[320px]">
          <div className="bg-white/70 backdrop-blur-2xl px-8 py-4 rounded-[2rem] shadow-2xl border border-white/50 flex items-center gap-4 animate-in slide-in-from-top duration-700">
            <div className="w-10 h-10 bg-emerald-500 text-white rounded-full flex items-center justify-center flex-shrink-0 animate-pulse">
