import { GoogleGenAI, Type } from "@google/genai";
import { DiseaseAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

export const analyzePlantDisease = async (base64Image: string): Promise<DiseaseAnalysis> => {
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: [
      {
        parts: [
          {
            inlineData: {
              mimeType: "image/jpeg",
              data: base64Image.split(',')[1] || base64Image,
            },
          },
          {
            text: "Analyze this plant health. Provide species, disease, severity, causes, treatment, and prevention. Also, suggest specific commercial fertilizer or pesticide categories. Include a confidence score (0.0 to 1.0). Return strictly JSON.",
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          species: { type: Type.STRING },
          diseaseName: { type: Type.STRING },
          severity: { type: Type.STRING },
          confidence: { type: Type.NUMBER },
          causes: { type: Type.ARRAY, items: { type: Type.STRING } },
          treatment: { type: Type.STRING },
          prevention: { type: Type.STRING },
          recommendedProducts: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
        required: ["species", "diseaseName", "severity", "confidence", "treatment", "recommendedProducts"],
      },
    },
  });

  const jsonStr = response.text?.trim() || "{}";
  return JSON.parse(jsonStr) as DiseaseAnalysis;
};

