import React, { useState, useRef } from 'react';
import { CameraView } from './CameraView';
import { MOCK_PLANTS } from '../constants';
import { Plant } from '../types';

interface PlacedPlant extends Plant {
  x: number;
  y: number;
  scale: number;
  id_instance: number;
}

export const ARVisualizer: React.FC = () => {
  const [placedPlants, setPlacedPlants] = useState<PlacedPlant[]>([]);
  const [selectedPlant, setSelectedPlant] = useState<Plant>(MOCK_PLANTS[0]);
  const containerRef = useRef<HTMLDivElement>(null);

  const addPlantToScene = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newInstance: PlacedPlant = {
      ...selectedPlant,
      x,
      y,
      scale: 1,
      id_instance: Date.now(),
    };
    setPlacedPlants([...placedPlants, newInstance]);
  };

  const updatePlant = (id: number, delta: number) => {
    setPlacedPlants(prev => prev.map(p => 
      p.id_instance === id ? { ...p, scale: Math.max(0.2, p.scale + delta) } : p
    ));
  };

  const removePlant = (id: number) => {
    setPlacedPlants(prev => prev.filter(p => p.id_instance !== id));
  };

  return (
    <div className="max-w-6xl mx-auto p-4 space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-4xl font-black text-slate-800 tracking-tighter">AR STUDIO</h2>
          <p className="text-slate-500 font-medium">Experiment with spatial placement in your environment.</p>
        </div>
        <div className="flex gap-3">
          {MOCK_PLANTS.map(p => (
            <button
              key={p.id}
              onClick={() => setSelectedPlant(p)}
              className={`w-14 h-14 rounded-2xl border-2 overflow-hidden transition-all bg-white shadow-sm ${
                selectedPlant.id === p.id ? 'border-emerald-500 scale-110 shadow-lg' : 'border-transparent opacity-60'
              }`}
            >
              <img src={p.imageUrl} alt={p.name} className="w-full h-full object-cover p-1" />
            </button>
          ))}
        </div>
      </div>

      <div 
        ref={containerRef}
        onClick={addPlantToScene}
        className="relative overflow-hidden rounded-[3rem] cursor-crosshair border-[10px] border-white shadow-2xl bg-slate-200"
      >
        <CameraView 
          isActive={true} 
          overlayContent={
            <div className="absolute inset-0 pointer-events-none">
              {placedPlants.map((p) => (
                <div
                  key={p.id_instance}
                  className="absolute pointer-events-auto group"
                  style={{
                    left: `${p.x}%`,
                    top: `${p.y}%`,
                    transform: `translate(-50%, -100%) scale(${p.scale})`,
                    zIndex: Math.floor(p.y),
                  }}
                >
                  <div className="relative">
                    <img 
                      src={p.imageUrl} 
                      alt={p.name} 
                      className="w-48 h-64 object-contain transition-all duration-500"
                      style={{ 
                        mixBlendMode: 'multiply',
                        filter: 'brightness(1.1) contrast(1.1) saturate(1.1)',
                        WebkitMaskImage: 'radial-gradient(circle at center, black 65%, transparent 100%)',
                      }}
                    />
                    {/* Shadow Layer */}
                    <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-3/4 h-4 bg-black/25 blur-xl rounded-full scale-y-[0.3] -z-10" />
                  </div>

                  <div className="absolute -top-14 left-1/2 -translate-x-1/2 hidden group-hover:flex bg-slate-900 text-white rounded-2xl p-1 gap-4 border border-white/20 px-4 py-2 shadow-2xl">
                    <button onClick={(e) => { e.stopPropagation(); updatePlant(p.id_instance, 0.1); }} className="hover:text-emerald-400 font-bold"><i className="fas fa-plus" /></button>
                    <button onClick={(e) => { e.stopPropagation(); updatePlant(p.id_instance, -0.1); }} className="hover:text-emerald-400 font-bold"><i className="fas fa-minus" /></button>
                    <button onClick={(e) => { e.stopPropagation(); removePlant(p.id_instance); }} className="hover:text-red-400 font-bold"><i className="fas fa-times" /></button>
                  </div>
                </div>
              ))}
            </div>
          }
        />
        <div className="absolute top-6 left-6 bg-emerald-600/80 backdrop-blur-md text-white px-4 py-2 rounded-full text-[10px] font-black tracking-widest animate-pulse border border-white/20">
          SPATIAL INDUCTION MODE
        </div>
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white/20 backdrop-blur-md px-6 py-2 rounded-2xl text-white text-[10px] font-bold border border-white/20">
          TAP SURFACE TO POSITION {selectedPlant.name.toUpperCase()}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { Plant, PlantCategory, UserRole } from '../types';

interface AdminPanelProps {
  plants: Plant[];
  userRole: UserRole;
  onAdd: (plant: Plant) => void;
  onRemove: (id: string) => void;
  onUpdateStock: (id: string, newStock: number) => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ plants, userRole, onAdd, onRemove, onUpdateStock }) => {
  const [view, setView] = useState<'inventory' | 'analytics' | 'orders'>('inventory');
  const [isAdding, setIsAdding] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Rate limiting simulation for sensitive actions
  const [lastActionTimestamp, setLastActionTimestamp] = useState(0);

  const [newPlant, setNewPlant] = useState<Partial<Plant>>({
    name: '',
    price: 0,
    category: PlantCategory.INDOOR,
    stock: 0,
  });

  // Security Check: Unauthorized access rejection
  if (userRole !== UserRole.BUSINESS_ADMIN && userRole !== UserRole.SUPER_ADMIN) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-red-500 animate-in fade-in duration-500">
        <i className="fas fa-shield-halved text-6xl mb-4" />
        <h3 className="text-2xl font-black uppercase tracking-tighter">Access Denied</h3>
        <p className="text-slate-500 font-bold text-sm mt-2">Unauthorized attempt detected. Your IP has been logged.</p>
      </div>
    );
  }

  const validateInput = (plant: Partial<Plant>): string | null => {
    if (!plant.name || plant.name.length < 3) return "Plant name must be at least 3 characters.";
    if (!plant.price || plant.price <= 0) return "Price must be a positive value.";
    if (plant.stock === undefined || plant.stock < 0) return "Stock cannot be negative.";
    return null;
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Rate Limiting: 2-second cooldown between plant additions
    const now = Date.now();
    if (now - lastActionTimestamp < 2000) {
      setError("Please wait before performing another action.");
      return;
    }

    const validationError = validateInput(newPlant);
    if (validationError) {
      setError(validationError);
      return;
    }

    // Input Sanitization (simulated)
    const sanitizedName = newPlant.name?.replace(/[<>]/g, '') || 'Unnamed Plant';

    const plantToSubmit = {
      ...newPlant,
      name: sanitizedName,
      id: Math.random().toString(36).substr(2, 9),
      size: 'Medium',
      growthStage: 'Sapling',
      sunlight: 'Bright Indirect',
      watering: 'Weekly',
      soil: 'Standard',
      description: 'System-verified plant entry.',
      maintenanceLevel: 'Easy',
      imageUrl: 'https://images.unsplash.com/photo-1545239351-ef35f43d514b?auto=format&fit=crop&w=400'
    } as Plant;

    onAdd(plantToSubmit);
    setIsAdding(false);
    setLastActionTimestamp(now);
    setNewPlant({ name: '', price: 0, category: PlantCategory.INDOOR, stock: 0 });
  };

  const totalRevenue = plants.reduce((acc, p) => acc + (p.price * p.stock), 0);
  const lowStockCount = plants.filter(p => p.stock < 5).length;

  return (
    <div className="max-w-7xl mx-auto space-y-8 pb-20">
      <div className="flex flex-col md:flex-row justify-between items-center gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-800 tracking-tighter flex items-center gap-3">
            <i className="fas fa-user-shield text-emerald-600 text-2xl" />
            ADMIN <span className="text-emerald-600">HUB</span>
          </h2>
          <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">
            Secure Management Session • {userRole.toUpperCase()}
          </p>
        </div>
        <div className="flex bg-slate-100 p-1.5 rounded-2xl shadow-inner border border-slate-200">
          {['inventory', 'analytics', 'orders'].map((v) => (
            <button 
              key={v}
              onClick={() => { setView(v as any); setError(null); }} 
              className={`px-6 py-2 rounded-xl font-black text-[10px] tracking-widest transition-all uppercase ${view === v ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              {v}
            </button>
          ))}
        </div>
      </div>

      {error && (
        <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-xl flex items-center gap-3 animate-in shake-in duration-300">
          <i className="fas fa-circle-exclamation text-red-500" />
          <p className="text-red-700 text-xs font-black uppercase tracking-wider">{error}</p>
        </div>
      )}

      {view === 'analytics' && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 animate-in fade-in duration-500">
          <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-slate-100 hover:border-emerald-200 transition-colors">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Portfolio Value</p>
            <h3 className="text-4xl font-black text-emerald-600">Rs. {totalRevenue.toLocaleString()}</h3>
          </div>
          <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-slate-100 hover:border-red-200 transition-colors">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Stock Alerts</p>
            <h3 className="text-4xl font-black text-red-500">{lowStockCount} Items</h3>
          </div>
        </div>
      )}

      {view === 'inventory' && (
        <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
          <div className="flex justify-between items-center px-4">
            <h3 className="text-xl font-black text-slate-800">Verified Catalog</h3>
            <button 
              onClick={() => setIsAdding(!isAdding)}
              className="bg-slate-900 text-white px-6 py-3 rounded-xl font-black text-[10px] tracking-widest hover:bg-emerald-600 transition-all flex items-center gap-2 shadow-lg"
            >
              <i className={`fas ${isAdding ? 'fa-times' : 'fa-plus-circle'}`} />
              {isAdding ? 'CANCEL' : 'REGISTER PLANT'}
            </button>
          </div>

          {isAdding && (
            <form onSubmit={handleAddSubmit} className="bg-slate-50 p-8 rounded-[2.5rem] border-2 border-slate-200 grid grid-cols-1 md:grid-cols-4 gap-6 animate-in zoom-in-95 duration-300">
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Name (Required)</label>
                <input required className="w-full p-3 bg-white rounded-xl border border-slate-200 font-bold text-sm focus:ring-2 focus:ring-emerald-500 outline-none" onChange={e => setNewPlant({...newPlant, name: e.target.value})} />
              </div>
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Price (PKR)</label>
                <input type="number" required className="w-full p-3 bg-white rounded-xl border border-slate-200 font-bold text-sm focus:ring-2 focus:ring-emerald-500 outline-none" onChange={e => setNewPlant({...newPlant, price: Number(e.target.value)})} />
              </div>
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Stock Level</label>
                <input type="number" required className="w-full p-3 bg-white rounded-xl border border-slate-200 font-bold text-sm focus:ring-2 focus:ring-emerald-500 outline-none" onChange={e => setNewPlant({...newPlant, stock: Number(e.target.value)})} />
              </div>
              <div className="flex items-end">
                <button type="submit" className="w-full bg-emerald-600 text-white py-3 rounded-xl font-black text-[10px] tracking-widest shadow-lg hover:bg-emerald-700 transition-colors">
                  VALIDATE & SAVE
                </button>
              </div>
            </form>
          )}

          <div className="bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100">
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Secure Asset</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Price</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Stock</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {plants.map(p => (
                  <tr key={p.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-8 py-5 flex items-center gap-4">
                      <img src={p.imageUrl} className="w-12 h-12 rounded-xl object-cover shadow-sm border border-slate-200" />
                      <span className="font-bold text-slate-800">{p.name}</span>
                    </td>
                    <td className="px-8 py-5 font-bold text-slate-600">Rs. {p.price.toLocaleString()}</td>
                    <td className="px-8 py-5">
                      <input 
                        type="number" 
                        value={p.stock} 
                        className={`w-16 p-2 bg-slate-100 rounded-lg text-center font-bold text-xs border border-transparent focus:border-emerald-500 outline-none ${p.stock < 5 ? 'text-red-500' : 'text-slate-700'}`}
                        onChange={(e) => onUpdateStock(p.id, Number(e.target.value))}
                      />
                    </td>
                    <td className="px-8 py-5">
                      <button 
                        onClick={() => { if(window.confirm('Confirm permanent deletion?')) onRemove(p.id); }} 
                        className="text-slate-300 hover:text-red-500 transition-colors p-2"
                      >
                        <i className="fas fa-trash-alt" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {view === 'orders' && (
        <div className="flex flex-col items-center justify-center py-20 text-slate-300">
          <i className="fas fa-lock text-6xl mb-4 opacity-10" />
          <p className="font-black text-[10px] uppercase tracking-widest">Orders database is encrypted and locked</p>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { MOCK_PLANTS } from './constants';
import { Plant, CartItem, UserRole, User } from './types';
import { PlantCard } from './components/PlantCard';
import { ARVisualizer } from './components/ARVisualizer';
import { DiseaseScanner } from './components/DiseaseScanner';
import { AdminPanel } from './components/AdminPanel';
import { LandscapeDesigner } from './components/LandscapeDesigner';
import { Auth } from './components/Auth';

type Tab = 'shop' | 'visualize' | 'doctor' | 'admin' | 'landscape' | 'history' | 'auth' | 'onboarding' | 'wishlist';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('shop');
  const [plants, setPlants] = useState<Plant[]>(MOCK_PLANTS.map(p => ({ ...p, stock: 10, maintenanceLevel: 'Easy', previewCount: Math.floor(Math.random() * 100) })));
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [deliveryMethod, setDeliveryMethod] = useState<'pickup' | 'express'>('pickup');
  const [hasOnboarded, setHasOnboarded] = useState(false);

  useEffect(() => {
    if (!hasOnboarded && activeTab === 'shop') {
      const timer = setTimeout(() => setActiveTab('onboarding'), 1000);
      return () => clearTimeout(timer);
    }
  }, [hasOnboarded]);

  const addToCart = (plant: Plant) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === plant.id);
      if (existing) {
        return prev.map(item => item.id === plant.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...plant, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleAuthRequired = (targetTab: Tab) => {
    if (!user) {
      setActiveTab('auth');
    } else {
      setActiveTab(targetTab);
    }
  };

  const toggleWishlist = (id: string) => {
    if (!user) {
      setActiveTab('auth');
      return;
    }
    const isWished = user.wishlist.includes(id);
    const newWishlist = isWished 
      ? user.wishlist.filter(wId => wId !== id)
      : [...user.wishlist, id];
    setUser({ ...user, wishlist: newWishlist });
  };

  const total = useMemo(() => {
    const subtotal = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);
    return subtotal + (deliveryMethod === 'express' ? 1500 : 0);
  }, [cart, deliveryMethod]);

  const displayedPlants = useMemo(() => {
    if (activeTab === 'wishlist' && user) {
      return plants.filter(p => user.wishlist.includes(p.id));
    }
    return plants;
  }, [activeTab, plants, user]);

  if (activeTab === 'onboarding') {
    return (
      <div className="fixed inset-0 z-[200] bg-emerald-950 flex items-center justify-center p-6">
        <div className="max-w-xl text-center space-y-8 animate-in zoom-in-95 duration-700">
          <div className="w-24 h-24 bg-emerald-500 rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl shadow-emerald-500/50">
            <i className="fas fa-seedling text-white text-4xl" />
          </div>
          <h1 className="text-5xl font-black text-white tracking-tighter">Grow Smarter.</h1>
          <p className="text-emerald-100/60 text-lg font-medium leading-relaxed">
            Welcome to FloraVision Pakistan. Discover plants, design your garden in AR, and use AI to keep your foliage healthy. 
          </p>
          <button 
            onClick={() => { setHasOnboarded(true); setActiveTab('shop'); }}
            className="bg-white text-emerald-900 px-12 py-5 rounded-[2rem] font-black text-lg hover:scale-105 transition-all"
          >
            EXPLORE GARDEN
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-24 lg:pb-0 bg-slate-50/50">
      <nav className="fixed bottom-0 left-0 right-0 z-50 bg-white/90 backdrop-blur-2xl border-t border-slate-100 lg:top-0 lg:bottom-0 lg:w-24 lg:border-r lg:border-t-0 flex lg:flex-col justify-around lg:justify-center items-center py-6">
        {[
          { id: 'shop', icon: 'fa-leaf', label: 'GARDEN' },
          { id: 'landscape', icon: 'fa-pencil-ruler', label: 'DESIGN' },
          { id: 'doctor', icon: 'fa-stethoscope', label: 'DOCTOR' },
          { id: 'wishlist', icon: 'fa-heart', label: 'SAVED' },
          { id: 'history', icon: 'fa-truck', label: 'ORDERS' }
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => (item.id !== 'shop' && item.id !== 'landscape' ? handleAuthRequired(item.id as Tab) : setActiveTab(item.id as Tab))} 
            className={`flex flex-col items-center gap-1 transition-all ${activeTab === item.id ? 'text-emerald-600 scale-110' : 'text-slate-300 hover:text-slate-400'}`}
          >
            <i className={`fas ${item.icon} text-2xl`} />
            <span className="text-[8px] font-black tracking-widest">{item.label}</span>
          </button>
        ))}
        {(user?.role === UserRole.BUSINESS_ADMIN || user?.role === UserRole.SUPER_ADMIN) && (
          <button onClick={() => setActiveTab('admin')} className={`mt-10 flex flex-col items-center gap-1 transition-all ${activeTab === 'admin' ? 'text-emerald-600' : 'text-slate-300'}`}>
            <i className="fas fa-chart-line text-2xl" />
            <span className="text-[8px] font-black tracking-widest">BIZ</span>
          </button>
        )}
      </nav>

      <main className="lg:ml-24">
        <header className="px-10 py-8 flex justify-between items-center bg-white/40 backdrop-blur-xl sticky top-0 z-40 border-b border-white/50">
          <div onClick={() => setActiveTab('shop')} className="cursor-pointer group">
            <h1 className="text-3xl font-black text-slate-800 tracking-tighter group-hover:text-emerald-600 transition-colors">FLORAVISION</h1>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em]">Smart Horticulture Platform • PKR</p>
          </div>

          <div className="flex items-center gap-6">
             {user ? (
               <div className="flex items-center gap-4 bg-white p-2 pr-6 rounded-full border border-slate-100">
                 <div className="w-10 h-10 bg-emerald-500 rounded-full flex items-center justify-center text-white font-black text-xs">
                   {user.email[0].toUpperCase()}
                 </div>
                 <div className="text-left">
                   <p className="text-[10px] font-black text-slate-400 uppercase leading-none">{user.role}</p>
                   <p className="text-xs font-bold text-slate-800 leading-tight">{user.email}</p>
                 </div>
                 <button onClick={() => setUser(null)} className="ml-2 text-slate-300 hover:text-red-500 transition-colors">
                   <i className="fas fa-power-off" />
                 </button>
               </div>
             ) : (
               <button onClick={() => setActiveTab('auth')} className="bg-slate-900 text-white px-8 py-3 rounded-2xl font-black text-xs hover:bg-emerald-600 transition-all shadow-xl shadow-slate-900/10">
                 CLIENT PORTAL
               </button>
             )}

             <button onClick={() => setIsCartOpen(true)} className="relative w-12 h-12 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center hover:scale-110 transition-transform">
               <i className="fas fa-shopping-bag text-lg" />
               {cart.length > 0 && <span className="absolute -top-1 -right-1 bg-emerald-500 text-white text-[10px] w-5 h-5 rounded-full border-2 border-white flex items-center justify-center font-black animate-bounce">{cart.length}</span>}
             </button>
          </div>
        </header>

        <div className="p-10 max-w-[1600px] mx-auto">
          {activeTab === 'auth' && <Auth onLogin={(u) => { setUser(u); setActiveTab('shop'); }} />}
          {(activeTab === 'shop' || activeTab === 'wishlist') && (
            <div className="space-y-10">
              {activeTab === 'wishlist' && (
                <div className="flex items-center gap-4 mb-8">
                  <div className="w-12 h-12 bg-red-100 text-red-500 rounded-2xl flex items-center justify-center text-xl">
                    <i className="fas fa-heart" />
                  </div>
                  <h2 className="text-3xl font-black text-slate-800 tracking-tight">Your Favorites</h2>
                </div>
              )}
              {displayedPlants.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 2xl:grid-cols-5 gap-10">
                  {displayedPlants.map(p => (
                    <PlantCard 
                      key={p.id} 
                      plant={p} 
                      onAddToCart={addToCart} 
                      onPreview={() => {
                        setPlants(prev => prev.map(item => item.id === p.id ? {...item, previewCount: (item.previewCount||0)+1} : item));
                        setActiveTab('landscape');
                      }} 
                      isWishlisted={user?.wishlist.includes(p.id)}
                      onToggleWishlist={toggleWishlist}
                    />
                  ))}
                </div>
              ) : (
                <div className="text-center py-20 bg-white rounded-[3rem] border border-slate-100">
                  <i className="fas fa-leaf text-6xl text-slate-100 mb-6" />
                  <p className="text-slate-400 font-bold uppercase tracking-widest text-sm">Nothing to show here</p>
                </div>
              )}
            </div>
          )}
          {activeTab === 'landscape' && <LandscapeDesigner />}
          {activeTab === 'doctor' && <DiseaseScanner />}
          {activeTab === 'admin' && user && (
            <AdminPanel 
              plants={plants} 
              userRole={user.role}
              onAdd={(p) => setPlants([...plants, p])} 
              onRemove={(id) => setPlants(plants.filter(p => p.id !== id))} 
              onUpdateStock={(id, stock) => setPlants(plants.map(p => p.id === id ? {...p, stock} : p))}
            />
          )}
          {activeTab === 'history' && user && (
            <div className="max-w-4xl mx-auto space-y-10">
              <div className="bg-white p-12 rounded-[3.5rem] shadow-sm border border-slate-100 flex items-center gap-10">
                <div className="w-20 h-20 bg-blue-50 text-blue-600 rounded-3xl flex items-center justify-center text-3xl">
                  <i className="fas fa-box-open" />
                </div>
                <div>
                  <h2 className="text-3xl font-black text-slate-800">Track Shipments</h2>
                  <p className="text-slate-400 font-medium">Real-time logistics data for your active orders.</p>
                </div>
              </div>
              {user.history.map(order => (
                <div key={order.id} className="bg-white p-10 rounded-[3rem] shadow-sm border border-slate-100">
                   <div className="flex justify-between items-center mb-8">
                     <div>
                       <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{order.date}</p>
                       <h4 className="text-xl font-black text-slate-800">Order #{order.id}</h4>
                     </div>
                     <span className="px-4 py-1 bg-emerald-100 text-emerald-700 rounded-full text-[10px] font-black">{order.status}</span>
                   </div>
                   <div className="relative h-2 bg-slate-50 rounded-full overflow-hidden mb-6">
                     <div className="absolute top-0 left-0 h-full bg-emerald-500 w-3/4" />
                   </div>
                   <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest">
                     <span>Warehouse</span>
                     <span>In Transit</span>
                     <span className="text-emerald-500">Arrived</span>
                   </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      {isCartOpen && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-xl" onClick={() => setIsCartOpen(false)} />
          <div className="relative w-full max-w-lg bg-white h-full shadow-2xl p-12 flex flex-col animate-in slide-in-from-right duration-500 border-l border-white/20">
            <h2 className="text-4xl font-black text-slate-800 mb-10 tracking-tighter">Your Bag</h2>
            <div className="flex-1 overflow-y-auto space-y-6 pr-4 no-scrollbar">
              {cart.map(item => (
                <div key={item.id} className="group flex gap-6 items-center p-6 bg-slate-50 rounded-[2.5rem] border border-transparent hover:border-emerald-200 transition-all">
                  <img src={item.imageUrl} className="w-24 h-24 object-cover rounded-3xl shadow-lg" />
                  <div className="flex-1">
                    <h4 className="font-black text-lg text-slate-800">{item.name}</h4>
                    <p className="text-xs font-bold text-slate-400">Rs. {item.price.toLocaleString()} • Qty {item.quantity}</p>
                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-slate-300 hover:text-red-500 transition-colors">
                    <i className="fas fa-trash" />
                  </button>
                </div>
              ))}
            </div>
            <div className="mt-10 pt-10 border-t border-slate-100 space-y-8">
               <div className="flex justify-between items-end">
                 <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Grand Total</p>
                 <p className="text-5xl font-black text-slate-900 tracking-tighter">Rs. {total.toLocaleString()}</p>
               </div>
