import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
  isAdminMode?: boolean;
}

export const Auth: React.FC<AuthProps> = ({ onLogin, isAdminMode = false }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Strict Admin Mode Validation
    if (isAdminMode && !email.includes('admin')) {
      setError("This portal is restricted to administrative staff only.");
      return;
    }

    // Simulate role-based auth
    const role = email.includes('admin') ? UserRole.BUSINESS_ADMIN : UserRole.CUSTOMER;

    const mockUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      role: role,
      isSubscribed: email.includes('pro'),
      wishlist: [],
      history: [
        { 
          id: 'order-7721', 
          date: 'Oct 12, 2024', 
          items: ['Monstera Deliciosa', 'Watering Can'], 
          total: 14500,
          status: 'Shipped'
        }
      ]
    };
    onLogin(mockUser);
  };

  return (
    <div className="max-w-md mx-auto py-12 px-4 animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className={`bg-white rounded-[3rem] shadow-2xl overflow-hidden border-2 p-10 transition-colors ${isAdminMode ? 'border-slate-800 shadow-slate-200' : 'border-slate-100 shadow-emerald-50'}`}>
        <div className="text-center mb-10">
          <div className={`w-16 h-16 rounded-3xl flex items-center justify-center mx-auto text-2xl mb-6 shadow-sm rotate-3 transition-colors ${isAdminMode ? 'bg-slate-900 text-white' : 'bg-emerald-100 text-emerald-600'}`}>
            <i className={`fas ${isAdminMode ? 'fa-user-shield' : 'fa-user-circle'}`} />
          </div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">
            {isAdminMode ? 'Admin Portal' : (isLogin ? 'Welcome Back' : 'Join FloraVision')}
          </h2>
          <p className="text-slate-400 font-bold text-xs uppercase mt-2 tracking-widest">
            {isAdminMode ? 'Restricted Access Area' : (isLogin ? 'Enter your details to sign in' : 'Start your pro gardening journey')}
          </p>

          {error && (
            <div className="mt-6 p-4 bg-red-50 text-red-600 rounded-2xl text-[10px] font-black uppercase tracking-wider animate-in shake-in duration-300">
              <i className="fas fa-circle-exclamation mr-2" />
              {error}
