          )}

          {!isAdminMode && (
            <div className="mt-4 p-2 bg-slate-50 rounded-lg text-[10px] text-slate-400 font-bold uppercase">
              Tip: Standard customer account access
            </div>
          )}
          {isAdminMode && !error && (
            <div className="mt-4 p-2 bg-slate-900 text-slate-400 rounded-lg text-[10px] font-bold uppercase">
              Authenticated session required
            </div>
          )}
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">Credentials Identifier</label>
            <input 
              type="email" required placeholder="admin@flora.com"
              className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-emerald-500 rounded-2xl outline-none transition-all font-bold text-slate-800"
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">Secret Key</label>
            <input 
              type="password" required placeholder="••••••••"
              className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-emerald-500 rounded-2xl outline-none transition-all font-bold text-slate-800"
            />
          </div>

          <button type="submit" className={`w-full py-5 rounded-2xl font-black text-lg transition-all shadow-xl ${isAdminMode ? 'bg-slate-900 hover:bg-slate-800 shadow-slate-300' : 'bg-emerald-600 hover:bg-emerald-500 shadow-emerald-100'} text-white`}>
            {isAdminMode ? 'AUTHORIZE ACCESS' : (isLogin ? 'SIGN IN' : 'CREATE ACCOUNT')}
          </button>

          {!isAdminMode && (
            <div className="text-center">
              <button 
                type="button" 
                onClick={() => setIsLogin(!isLogin)} 
                className="text-sm font-black text-emerald-600 hover:text-emerald-700 transition-colors"
              >
                {isLogin ? "Need an account? Sign Up" : "Already have an account? Log In"}
              </button>
            </div>
          )}
        </form>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { CameraView } from './CameraView';
import { MOCK_PLANTS, GARDEN_TOOLS } from '../constants';
import { LandscapeItem, Plant, Tool } from '../types';

type DesignMode = 'static' | 'live';
type Category = 'plants' | 'objects' | 'surfaces';

interface SavedDesign {
  id: string;
  name: string;
  items: LandscapeItem[];
  bgImage?: string;
}

export const LandscapeDesigner: React.FC = () => {
  const [items, setItems] = useState<LandscapeItem[]>([]);
  const [designMode, setDesignMode] = useState<DesignMode>('static');
  const [activeCategory, setActiveCategory] = useState<Category>('plants');
  const [selectedItemId, setSelectedItemId] = useState<string>(MOCK_PLANTS[0].id);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [currentDesignName, setCurrentDesignName] = useState('New Concept');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Surface textures for landscaping
  const SURFACE_ASSETS = [
    { id: 's1', name: 'Premium Turf', imageUrl: 'https://images.unsplash.com/photo-1533460004989-cef01064af7c?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's2', name: 'Gravel Path', imageUrl: 'https://images.unsplash.com/photo-1508182314998-3bd49473002f?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's3', name: 'Paved Walkway', imageUrl: 'https://images.unsplash.com/photo-1590059392253-df2676f4e183?auto=format&fit=crop&w=400', type: 'surface' }
  ];

  const currentPalette = useMemo(() => {
    if (activeCategory === 'plants') return MOCK_PLANTS;
    if (activeCategory === 'objects') return GARDEN_TOOLS;
    return SURFACE_ASSETS;
  }, [activeCategory]);

  const aiSuggestions = useMemo(() => {
    const itemCount = items.length;
    const hasTrees = items.some(i => MOCK_PLANTS.find(p => p.id === i.itemId)?.category === 'Tree');
    const hasSurfaces = items.some(i => i.type === 'tool' && i.itemId.startsWith('s'));

    if (itemCount === 0) return "Choose a base surface or plant a tree to define the boundary.";
    if (!hasSurfaces && itemCount > 2) return "Try adding 'Premium Turf' to unify the organic elements.";
    if (!hasTrees && designMode === 'live') return "Vertical scale is low. Anchor a tree in the mid-ground for better perspective.";
    return "Composition looks balanced. Consider path lighting for night-time visibility.";
  }, [items, designMode]);

  const addItem = (e: React.MouseEvent<HTMLDivElement>) => {
    if (designMode === 'static' && !uploadedImage && !e.shiftKey) return;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newItem: LandscapeItem = {
      instanceId: Math.random().toString(36).substr(2, 9),
      itemId: selectedItemId,
      type: activeCategory === 'plants' ? 'plant' : 'tool',
      x, y, rotation: 0, scale: activeCategory === 'surfaces' ? 2 : 1
    };
    setItems([...items, newItem]);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (re) => setUploadedImage(re.target?.result as string);
      reader.readAsDataURL(file);
      setDesignMode('static');
    }
  };

  const saveDesign = () => {
    const newDesign: SavedDesign = {
      id: Date.now().toString(),
      name: currentDesignName,
      items: [...items],
      bgImage: uploadedImage || undefined
    };
    setSavedDesigns([...savedDesigns, newDesign]);
    alert("Design configuration saved successfully.");
  };

  const loadDesign = (design: SavedDesign) => {
    setItems(design.items);
    if (design.bgImage) {
      setUploadedImage(design.bgImage);
      setDesignMode('static');
    } else {
      setDesignMode('live');
    }
    setCurrentDesignName(design.name);
  };

  const removeItem = (id: string) => setItems(items.filter(i => i.instanceId !== id));

  const getItemData = (item: LandscapeItem) => {
    return [...MOCK_PLANTS, ...GARDEN_TOOLS, ...SURFACE_ASSETS].find(x => x.id === item.itemId);
  };

  return (
    <div className="max-w-[1600px] mx-auto space-y-6 pb-12 animate-in fade-in duration-1000">
      {/* Upper Control Bar */}
