              >
                <i className="fas fa-trash-alt text-sm" />
              </button>
            </div>
          </div>
        );
      })}
    </>
  );
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { CameraView } from './CameraView';
import { MOCK_PLANTS, GARDEN_TOOLS } from '../constants';
import { LandscapeItem, Plant, Tool } from '../types';

type DesignMode = 'static' | 'live';
type Category = 'plants' | 'objects' | 'surfaces';

interface SavedDesign {
  id: string;
  name: string;
  items: LandscapeItem[];
  bgImage?: string;
}

export const LandscapeDesigner: React.FC = () => {
  const [items, setItems] = useState<LandscapeItem[]>([]);
  const [history, setHistory] = useState<LandscapeItem[][]>([]);
  const [designMode, setDesignMode] = useState<DesignMode>('static');
  const [activeCategory, setActiveCategory] = useState<Category>('plants');
  const [selectedItemId, setSelectedItemId] = useState<string>(MOCK_PLANTS[0].id);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [currentDesignName, setCurrentDesignName] = useState('New Concept');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const SURFACE_ASSETS = [
    { id: 's1', name: 'Premium Turf', imageUrl: 'https://images.unsplash.com/photo-1533460004989-cef01064af7c?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's2', name: 'Gravel Path', imageUrl: 'https://images.unsplash.com/photo-1508182314998-3bd49473002f?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's3', name: 'Paved Walkway', imageUrl: 'https://images.unsplash.com/photo-1590059392253-df2676f4e183?auto=format&fit=crop&w=400', type: 'surface' }
  ];

  const currentPalette = useMemo(() => {
    if (activeCategory === 'plants') return MOCK_PLANTS;
    if (activeCategory === 'objects') return GARDEN_TOOLS;
    return SURFACE_ASSETS;
  }, [activeCategory]);

  const getItemData = (itemId: string) => {
    return [...MOCK_PLANTS, ...GARDEN_TOOLS, ...SURFACE_ASSETS].find(x => x.id === itemId);
  };

  // AI SPACING LOGIC
  const proximityAlerts = useMemo(() => {
    const alerts: Record<string, boolean> = {};
    items.forEach((item, i) => {
      items.forEach((other, j) => {
        if (i === j) return;
        const dx = item.x - other.x;
        const dy = item.y - other.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        // Define safe distance: Trees need 15%, Shrubs 8%, Surfaces are ignoreable
        const itemData = getItemData(item.itemId);
        const threshold = itemData?.category === 'Tree' ? 12 : 6;

        if (distance < threshold) {
          alerts[item.instanceId] = true;
          alerts[other.instanceId] = true;
        }
      });
    });
    return alerts;
  }, [items]);

  const aiSuggestions = useMemo(() => {
    const itemCount = items.length;
    const overcrowded = Object.values(proximityAlerts).filter(v => v).length;

    if (overcrowded > 0) return "WARNING: Some plants are too close for healthy root growth. Space them out for long-term health.";
    if (itemCount === 0) return "Ready to design? Start with a large tree to establish a focal point.";
    if (itemCount > 0 && itemCount < 3) return "Looking good! Add a surface texture like 'Premium Turf' to ground your design.";
    return "Composition balanced. Your layout maximizes sunlight exposure for all layers.";
  }, [items, proximityAlerts]);

  const addItem = (e: React.MouseEvent<HTMLDivElement>) => {
    if (designMode === 'static' && !uploadedImage && !e.shiftKey) return;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    // Auto-adjustment: If we tap too close to another item, nudge slightly
    let finalX = x;
    let finalY = y;
    items.forEach(other => {
      const dx = x - other.x;
      const dy = y - other.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 4) {
        finalX += 5; // Nudge right
      }
    });

    const newItem: LandscapeItem = {
      instanceId: Math.random().toString(36).substr(2, 9),
      itemId: selectedItemId,
      type: activeCategory === 'plants' ? 'plant' : 'tool',
      x: finalX, y: finalY, rotation: 0, scale: activeCategory === 'surfaces' ? 2 : 1
    };

    setHistory([...history, items]);
    setItems([...items, newItem]);
  };

  const handleUndo = () => {
    if (history.length > 0) {
      const prev = history[history.length - 1];
      setItems(prev);
      setHistory(history.slice(0, -1));
    }
  };

  const handleReset = () => {
    if (confirm("Reset current design? This cannot be undone.")) {
      setHistory([...history, items]);
      setItems([]);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (re) => setUploadedImage(re.target?.result as string);
      reader.readAsDataURL(file);
      setDesignMode('static');
    }
  };

  const saveDesign = () => {
    const newDesign: SavedDesign = {
      id: Date.now().toString(),
      name: currentDesignName,
      items: [...items],
      bgImage: uploadedImage || undefined
    };
    setSavedDesigns([...savedDesigns, newDesign]);
  };

  const loadDesign = (design: SavedDesign) => {
    setHistory([...history, items]);
    setItems(design.items);
    if (design.bgImage) {
      setUploadedImage(design.bgImage);
      setDesignMode('static');
    } else {
      setDesignMode('live');
    }
    setCurrentDesignName(design.name);
  };

  const removeItem = (id: string) => {
    setHistory([...history, items]);
    setItems(items.filter(i => i.instanceId !== id));
  };

  return (
    <div className="max-w-[1600px] mx-auto space-y-6 pb-12 animate-in fade-in duration-1000">
      <div className="flex flex-col md:flex-row justify-between items-center gap-6 bg-white p-6 rounded-[3rem] shadow-xl border border-slate-100">
        <div className="flex items-center gap-6">
          <div className="flex bg-slate-100 p-1.5 rounded-[2rem]">
            <button 
              onClick={() => setDesignMode('static')}
              className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all flex items-center gap-2 ${designMode === 'static' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-image" /> STATIC
            </button>
            <button 
              onClick={() => setDesignMode('live')}
              className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all flex items-center gap-2 ${designMode === 'live' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-video" /> LIVE AR
            </button>
          </div>

          <div className="flex gap-2">
            <button onClick={handleUndo} disabled={history.length === 0} className="w-10 h-10 bg-slate-100 text-slate-600 rounded-xl hover:bg-slate-200 disabled:opacity-30 transition-all flex items-center justify-center">
              <i className="fas fa-undo" />
            </button>
            <button onClick={handleReset} className="w-10 h-10 bg-slate-100 text-red-500 rounded-xl hover:bg-red-50 transition-all flex items-center justify-center">
              <i className="fas fa-trash-can" />
            </button>
          </div>
        </div>

        <div className="flex gap-3">
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl font-black text-[10px] tracking-widest hover:bg-slate-200 transition-all uppercase"
          >
            Site Photo
          </button>
          <button 
            onClick={saveDesign}
            className="bg-emerald-600 text-white px-8 py-3 rounded-2xl font-black text-[10px] tracking-widest hover:bg-emerald-700 transition-all uppercase shadow-lg"
          >
            Save Design
          </button>
          <input ref={fileInputRef} type="file" hidden accept="image/*" onChange={handleFileUpload} />
        </div>
      </div>

      <div className="grid lg:grid-cols-4 gap-8">
        <div className="lg:col-span-3 relative h-[70vh] rounded-[4rem] overflow-hidden border-[12px] border-white shadow-2xl bg-slate-100">
          <div 
            ref={containerRef}
            onClick={addItem}
            className="w-full h-full relative cursor-crosshair"
          >
            {designMode === 'live' ? (
              <CameraView 
                isActive={true} 
                overlayContent={
                  <div className="absolute inset-0 pointer-events-none">
                    <DesignerOverlay items={items} getItemData={getItemData} onRemove={removeItem} alerts={proximityAlerts} />
                  </div>
                }
              />
            ) : (
              <div className="w-full h-full flex items-center justify-center bg-slate-100 relative">
                {uploadedImage ? (
                  <img src={uploadedImage} className="w-full h-full object-cover" />
                ) : (
                  <div className="text-center space-y-4 opacity-30">
                    <i className="fas fa-cloud-upload-alt text-6xl" />
                    <p className="font-black text-sm uppercase tracking-widest">Upload garden image or switch to LIVE AR</p>
                  </div>
                )}
                <div className="absolute inset-0 pointer-events-none">
                  <DesignerOverlay items={items} getItemData={getItemData} onRemove={removeItem} alerts={proximityAlerts} />
                </div>
              </div>
            )}
          </div>

          <div className="absolute top-8 right-8 pointer-events-none">
             <div className={`glass-card p-6 rounded-[2.5rem] border transition-all max-w-xs shadow-2xl ${Object.keys(proximityAlerts).length > 0 ? 'border-red-500/50' : 'border-white/40'}`}>
                <p className={`text-[9px] font-black uppercase tracking-widest mb-2 flex items-center gap-2 ${Object.keys(proximityAlerts).length > 0 ? 'text-red-600' : 'text-emerald-700'}`}>
                  <i className={`fas ${Object.keys(proximityAlerts).length > 0 ? 'fa-triangle-exclamation' : 'fa-sparkles'}`} /> AI SPACING ASSIST
                </p>
                <p className="text-xs font-bold text-slate-800 leading-relaxed italic">"{aiSuggestions}"</p>
             </div>
          </div>

          <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-slate-900/90 backdrop-blur-xl p-2 rounded-[2.5rem] shadow-2xl border border-white/10">
            {(['plants', 'objects', 'surfaces'] as Category[]).map(cat => (
              <button 
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`px-6 py-2.5 rounded-full font-black text-[9px] tracking-widest uppercase transition-all ${activeCategory === cat ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-8 h-[70vh] flex flex-col">
          <div className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm flex-1 overflow-hidden flex flex-col">
            <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6 flex items-center gap-3">
              <i className="fas fa-seedling text-emerald-600" />
              Components
            </h4>
            <div className="flex-1 overflow-y-auto pr-2 space-y-4 no-scrollbar">
              {currentPalette.map((p: any) => (
                <button 
                  key={p.id}
                  onClick={() => setSelectedItemId(p.id)}
                  className={`w-full group flex items-center gap-4 p-3 rounded-2xl border-2 transition-all ${selectedItemId === p.id ? 'bg-emerald-50 border-emerald-500' : 'bg-white border-transparent hover:border-slate-50'}`}
                >
                  <img src={p.imageUrl} className="w-12 h-12 rounded-xl object-cover" />
                  <div className="text-left">
                    <p className={`text-[11px] font-black uppercase ${selectedItemId === p.id ? 'text-emerald-700' : 'text-slate-800'}`}>{p.name}</p>
                    <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">{p.category || 'Asset'}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>

          <div className="bg-slate-900 p-8 rounded-[3.5rem] shadow-2xl text-white">
            <h4 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">Saved Concepts</h4>
            <div className="space-y-3 max-h-48 overflow-y-auto no-scrollbar">
              {savedDesigns.length === 0 ? (
                <p className="text-[10px] text-slate-500 font-bold uppercase text-center py-4">No drafts</p>
              ) : (
                savedDesigns.map(d => (
                  <button 
                    key={d.id} 
                    onClick={() => loadDesign(d)}
                    className="w-full flex justify-between items-center p-4 bg-white/5 rounded-2xl hover:bg-white/10 transition-colors"
                  >
                    <span className="text-xs font-black">{d.name}</span>
                    <i className="fas fa-chevron-right text-[10px]" />
                  </button>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

interface DesignerOverlayProps {
  items: LandscapeItem[];
  getItemData: (itemId: string) => any;
  onRemove: (id: string) => void;
  alerts: Record<string, boolean>;
}

const DesignerOverlay: React.FC<DesignerOverlayProps> = ({ items, getItemData, onRemove, alerts }) => {
  return (
    <>
      {items.map((item) => {
        const data = getItemData(item.itemId);
        const isSurface = item.itemId.startsWith('s');
        const hasAlert = alerts[item.instanceId];

        return (
          <div
            key={item.instanceId}
            className="absolute pointer-events-auto group/item animate-in zoom-in-50 duration-500"
            style={{
              left: `${item.x}%`,
              top: `${item.y}%`,
              transform: `translate(-50%, -100%) scale(${item.scale})`,
              zIndex: isSurface ? 1 : Math.floor(item.y)
            }}
          >
            <div className="relative">
              {hasAlert && (
                <div className="absolute inset-0 -m-2 border-4 border-red-500/50 rounded-full animate-pulse blur-sm" />
              )}

              <div className="relative">
                 <img 
                  src={data?.imageUrl} 
                  className={`${isSurface ? 'w-64 h-48 rounded-[2rem]' : item.type === 'plant' ? 'w-56 h-72' : 'w-28 h-28'} object-cover transition-all duration-700`}
                  style={{ 
                    filter: `brightness(1.1) contrast(${isSurface ? 0.9 : 1.1})`,
                    WebkitMaskImage: !isSurface ? 'radial-gradient(circle at center, black 70%, transparent 100%)' : 'none',
                    opacity: isSurface ? 0.7 : 1
                  }}
                />
              </div>

              {!isSurface && (
                <div className="absolute -bottom-3 left-1/2 -translate-x-1/2 w-[80%] h-5 bg-black/30 blur-2xl rounded-full scale-y-[0.3] -z-10" />
              )}
            </div>

            <div className="absolute -top-12 left-1/2 -translate-x-1/2 opacity-0 group-hover/item:opacity-100 flex gap-1 bg-white p-1.5 rounded-xl shadow-2xl transition-all scale-90">
              <button 
                 onClick={(e) => { e.stopPropagation(); onRemove(item.instanceId); }}
                 className="bg-red-500 text-white w-8 h-8 rounded-lg flex items-center justify-center hover:bg-red-600 shadow-md"
              >
                <i className="fas fa-trash-alt text-xs" />
              </button>
            </div>
          </div>
        );
      })}
    </>
  );
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { CameraView } from './CameraView';
import { MOCK_PLANTS, GARDEN_TOOLS } from '../constants';
import { LandscapeItem, Plant, Tool } from '../types';

type DesignMode = 'static' | 'live';
type Category = 'plants' | 'objects' | 'surfaces';

interface SavedDesign {
  id: string;
  name: string;
  items: LandscapeItem[];
  bgImage?: string;
}

export const LandscapeDesigner: React.FC = () => {
  const [items, setItems] = useState<LandscapeItem[]>([]);
  const [history, setHistory] = useState<LandscapeItem[][]>([]);
  const [designMode, setDesignMode] = useState<DesignMode>('static');
  const [activeCategory, setActiveCategory] = useState<Category>('plants');
  const [selectedItemId, setSelectedItemId] = useState<string>(MOCK_PLANTS[0].id);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [currentDesignName, setCurrentDesignName] = useState('New Concept');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const SURFACE_ASSETS = [
    { id: 's1', name: 'Premium Turf', imageUrl: 'https://images.unsplash.com/photo-1533460004989-cef01064af7c?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's2', name: 'Gravel Path', imageUrl: 'https://images.unsplash.com/photo-1508182314998-3bd49473002f?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's3', name: 'Paved Walkway', imageUrl: 'https://images.unsplash.com/photo-1590059392253-df2676f4e183?auto=format&fit=crop&w=400', type: 'surface' }
  ];

  const currentPalette = useMemo(() => {
    if (activeCategory === 'plants') return MOCK_PLANTS;
    if (activeCategory === 'objects') return GARDEN_TOOLS;
    return SURFACE_ASSETS;
  }, [activeCategory]);

  const getItemData = (itemId: string) => {
    return [...MOCK_PLANTS, ...GARDEN_TOOLS, ...SURFACE_ASSETS].find(x => x.id === itemId);
  };

  // AI SPACING LOGIC
  const proximityAlerts = useMemo(() => {
    const alerts: Record<string, boolean> = {};
    items.forEach((item, i) => {
      items.forEach((other, j) => {
        if (i === j) return;
        const dx = item.x - other.x;
        const dy = item.y - other.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        // Define safe distance: Trees need 15%, Shrubs 8%, Surfaces are ignoreable
        const itemData = getItemData(item.itemId);
        // FIX: Ensure category exists by checking if the item is a Plant or Tool. Surface assets use 'type' instead of 'category'.
        const category = (itemData as Plant)?.category || (itemData as Tool)?.category;
        const threshold = category === 'Tree' ? 12 : 6;

        if (distance < threshold) {
          alerts[item.instanceId] = true;
          alerts[other.instanceId] = true;
        }
      });
    });
    return alerts;
  }, [items]);

  const aiSuggestions = useMemo(() => {
    const itemCount = items.length;
    const overcrowded = Object.values(proximityAlerts).filter(v => v).length;

    if (overcrowded > 0) return "WARNING: Some plants are too close for healthy root growth. Space them out for long-term health.";
    if (itemCount === 0) return "Ready to design? Start with a large tree to establish a focal point.";
    if (itemCount > 0 && itemCount < 3) return "Looking good! Add a surface texture like 'Premium Turf' to ground your design.";
    return "Composition balanced. Your layout maximizes sunlight exposure for all layers.";
  }, [items, proximityAlerts]);

  const addItem = (e: React.MouseEvent<HTMLDivElement>) => {
    if (designMode === 'static' && !uploadedImage && !e.shiftKey) return;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    // Auto-adjustment: If we tap too close to another item, nudge slightly
    let finalX = x;
    let finalY = y;
    items.forEach(other => {
      const dx = x - other.x;
      const dy = y - other.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < 4) {
        finalX += 5; // Nudge right
      }
    });

    const newItem: LandscapeItem = {
      instanceId: Math.random().toString(36).substr(2, 9),
      itemId: selectedItemId,
      type: activeCategory === 'plants' ? 'plant' : 'tool',
      x: finalX, y: finalY, rotation: 0, scale: activeCategory === 'surfaces' ? 2 : 1
    };

    setHistory([...history, items]);
    setItems([...items, newItem]);
  };

  const handleUndo = () => {
    if (history.length > 0) {
      const prev = history[history.length - 1];
      setItems(prev);
      setHistory(history.slice(0, -1));
    }
  };

  const handleReset = () => {
    if (confirm("Reset current design? This cannot be undone.")) {
      setHistory([...history, items]);
      setItems([]);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (re) => setUploadedImage(re.target?.result as string);
      reader.readAsDataURL(file);
      setDesignMode('static');
    }
  };

  const saveDesign = () => {
    const newDesign: SavedDesign = {
      id: Date.now().toString(),
      name: currentDesignName,
      items: [...items],
      bgImage: uploadedImage || undefined
    };
    setSavedDesigns([...savedDesigns, newDesign]);
  };

  const loadDesign = (design: SavedDesign) => {
    setHistory([...history, items]);
    setItems(design.items);
    if (design.bgImage) {
      setUploadedImage(design.bgImage);
      setDesignMode('static');
    } else {
      setDesignMode('live');
    }
    setCurrentDesignName(design.name);
  };

  const removeItem = (id: string) => {
    setHistory([...history, items]);
    setItems(items.filter(i => i.instanceId !== id));
  };

  return (
    <div className="max-w-[1600px] mx-auto space-y-6 pb-12 animate-in fade-in duration-1000">
      <div className="flex flex-col md:flex-row justify-between items-center gap-6 bg-white p-6 rounded-[3rem] shadow-xl border border-slate-100">
        <div className="flex items-center gap-6">
          <div className="flex bg-slate-100 p-1.5 rounded-[2rem]">
            <button 
              onClick={() => setDesignMode('static')}
              className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all flex items-center gap-2 ${designMode === 'static' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-image" /> STATIC
            </button>
            <button 
              onClick={() => setDesignMode('live')}
              className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all flex items-center gap-2 ${designMode === 'live' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-video" /> LIVE AR
            </button>
          </div>

          <div className="flex gap-2">
            <button onClick={handleUndo} disabled={history.length === 0} className="w-10 h-10 bg-slate-100 text-slate-600 rounded-xl hover:bg-slate-200 disabled:opacity-30 transition-all flex items-center justify-center">
              <i className="fas fa-undo" />
            </button>
            <button onClick={handleReset} className="w-10 h-10 bg-slate-100 text-red-500 rounded-xl hover:bg-red-50 transition-all flex items-center justify-center">
              <i className="fas fa-trash-can" />
            </button>
          </div>
        </div>

        <div className="flex gap-3">
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl font-black text-[10px] tracking-widest hover:bg-slate-200 transition-all uppercase"
          >
            Site Photo
          </button>
          <button 
            onClick={saveDesign}
            className="bg-emerald-600 text-white px-8 py-3 rounded-2xl font-black text-[10px] tracking-widest hover:bg-emerald-700 transition-all uppercase shadow-lg"
          >
            Save Design
          </button>
          <input ref={fileInputRef} type="file" hidden accept="image/*" onChange={handleFileUpload} />
        </div>
      </div>

      <div className="grid lg:grid-cols-4 gap-8">
        <div className="lg:col-span-3 relative h-[70vh] rounded-[4rem] overflow-hidden border-[12px] border-white shadow-2xl bg-slate-100">
          <div 
            ref={containerRef}
            onClick={addItem}
            className="w-full h-full relative cursor-crosshair"
          >
            {designMode === 'live' ? (
              <CameraView 
                isActive={true} 
                overlayContent={
                  <div className="absolute inset-0 pointer-events-none">
                    <DesignerOverlay items={items} getItemData={getItemData} onRemove={removeItem} alerts={proximityAlerts} />
                  </div>
                }
              />
            ) : (
              <div className="w-full h-full flex items-center justify-center bg-slate-100 relative">
                {uploadedImage ? (
                  <img src={uploadedImage} className="w-full h-full object-cover" />
                ) : (
                  <div className="text-center space-y-4 opacity-30">
                    <i className="fas fa-cloud-upload-alt text-6xl" />
                    <p className="font-black text-sm uppercase tracking-widest">Upload garden image or switch to LIVE AR</p>
                  </div>
                )}
                <div className="absolute inset-0 pointer-events-none">
                  <DesignerOverlay items={items} getItemData={getItemData} onRemove={removeItem} alerts={proximityAlerts} />
                </div>
              </div>
            )}
          </div>

          <div className="absolute top-8 right-8 pointer-events-none">
             <div className={`glass-card p-6 rounded-[2.5rem] border transition-all max-w-xs shadow-2xl ${Object.keys(proximityAlerts).length > 0 ? 'border-red-500/50' : 'border-white/40'}`}>
                <p className={`text-[9px] font-black uppercase tracking-widest mb-2 flex items-center gap-2 ${Object.keys(proximityAlerts).length > 0 ? 'text-red-600' : 'text-emerald-700'}`}>
                  <i className={`fas ${Object.keys(proximityAlerts).length > 0 ? 'fa-triangle-exclamation' : 'fa-sparkles'}`} /> AI SPACING ASSIST
                </p>
                <p className="text-xs font-bold text-slate-800 leading-relaxed italic">"{aiSuggestions}"</p>
             </div>
          </div>

          <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-slate-900/90 backdrop-blur-xl p-2 rounded-[2.5rem] shadow-2xl border border-white/10">
            {(['plants', 'objects', 'surfaces'] as Category[]).map(cat => (
              <button 
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className={`px-6 py-2.5 rounded-full font-black text-[9px] tracking-widest uppercase transition-all ${activeCategory === cat ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-8 h-[70vh] flex flex-col">
          <div className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm flex-1 overflow-hidden flex flex-col">
            <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6 flex items-center gap-3">
              <i className="fas fa-seedling text-emerald-600" />
              Components
            </h4>
            <div className="flex-1 overflow-y-auto pr-2 space-y-4 no-scrollbar">
              {currentPalette.map((p: any) => (
                <button 
                  key={p.id}
                  onClick={() => setSelectedItemId(p.id)}
                  className={`w-full group flex items-center gap-4 p-3 rounded-2xl border-2 transition-all ${selectedItemId === p.id ? 'bg-emerald-50 border-emerald-500' : 'bg-white border-transparent hover:border-slate-50'}`}
                >
                  <img src={p.imageUrl} className="w-12 h-12 rounded-xl object-cover" />
                  <div className="text-left">
                    <p className={`text-[11px] font-black uppercase ${selectedItemId === p.id ? 'text-emerald-700' : 'text-slate-800'}`}>{p.name}</p>
                    <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">{p.category || 'Asset'}</p>
                  </div>
                </button>
              ))}
            </div>
          </div>

          <div className="bg-slate-900 p-8 rounded-[3.5rem] shadow-2xl text-white">
            <h4 className="text-xs font-black uppercase tracking-widest text-slate-400 mb-4">Saved Concepts</h4>
            <div className="space-y-3 max-h-48 overflow-y-auto no-scrollbar">
              {savedDesigns.length === 0 ? (
                <p className="text-[10px] text-slate-500 font-bold uppercase text-center py-4">No drafts</p>
              ) : (
                savedDesigns.map(d => (
                  <button 
                    key={d.id} 
                    onClick={() => loadDesign(d)}
                    className="w-full flex justify-between items-center p-4 bg-white/5 rounded-2xl hover:bg-white/10 transition-colors"
                  >
                    <span className="text-xs font-black">{d.name}</span>
                    <i className="fas fa-chevron-right text-[10px]" />
                  </button>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

