  return (
    <>
      {items.map((item) => {
        const data = getItemData(item.itemId);
        const isSurface = item.itemId.startsWith('s');
        const hasAlert = alerts[item.instanceId];

        return (
          <div
            key={item.instanceId}
            className="absolute pointer-events-auto group/item animate-in zoom-in-50 duration-500"
            style={{
              left: `${item.x}%`,
              top: `${item.y}%`,
              transform: `translate(-50%, -100%) scale(${item.scale})`,
              zIndex: isSurface ? 1 : Math.floor(item.y)
            }}
