                 <img 
                  src={data?.imageUrl} 
                  className={`${isSurface ? 'w-64 h-48 rounded-[2rem]' : item.type === 'plant' ? 'w-56 h-72' : 'w-28 h-28'} object-cover transition-all duration-700`}
                  style={{ 
                    filter: `brightness(1.1) contrast(${isSurface ? 0.9 : 1.1})`,
                    WebkitMaskImage: !isSurface ? 'radial-gradient(circle at center, black 70%, transparent 100%)' : 'none',
                    opacity: isSurface ? 0.7 : 1
                  }}
                />
              </div>

              {!isSurface && (
                <div className="absolute -bottom-3 left-1/2 -translate-x-1/2 w-[80%] h-5 bg-black/30 blur-2xl rounded-full scale-y-[0.3] -z-10" />
              )}
            </div>

            <div className="absolute -top-12 left-1/2 -translate-x-1/2 opacity-0 group-hover/item:opacity-100 flex gap-1 bg-white p-1.5 rounded-xl shadow-2xl transition-all scale-90">
              <button 
                 onClick={(e) => { e.stopPropagation(); onRemove(item.instanceId); }}
                 className="bg-red-500 text-white w-8 h-8 rounded-lg flex items-center justify-center hover:bg-red-600 shadow-md"
              >
                <i className="fas fa-trash-alt text-xs" />
              </button>
            </div>
          </div>
        );
      })}
    </>
  );
}

import React, { useState, useRef, useMemo } from 'react';
import { CameraView } from './CameraView';
import { MOCK_PLANTS } from '../constants';
import { Plant } from '../types';

interface PlacedPlant extends Plant {
  x: number;
  y: number;
  scale: number;
  rotation: number;
  id_instance: number;
}

type ViewMode = 'blueprint' | 'spatial';

export const ARVisualizer: React.FC = () => {
  const [placedPlants, setPlacedPlants] = useState<PlacedPlant[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('spatial');
  const [selectedPlant, setSelectedPlant] = useState<Plant>(MOCK_PLANTS[0]);
  const [uploadedBg, setUploadedBg] = useState<string | null>(null);
  const [activeInstance, setActiveInstance] = useState<number | null>(null);
  const [savedPreviews, setSavedPreviews] = useState<{id: string, name: string, items: PlacedPlant[]}[]>([]);

  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (re) => {
        setUploadedBg(re.target?.result as string);
        setViewMode('blueprint');
      };
      reader.readAsDataURL(file);
    }
  };

  const addPlantToScene = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    if (viewMode === 'blueprint' && !uploadedBg && !e.shiftKey) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newInstance: PlacedPlant = {
      ...selectedPlant,
      x,
      y,
      scale: 1,
      rotation: 0,
      id_instance: Date.now(),
    };
    setPlacedPlants([...placedPlants, newInstance]);
    setActiveInstance(newInstance.id_instance);
  };

  const updatePlant = (id: number, type: 'scale' | 'rotate', delta: number) => {
    setPlacedPlants(prev => prev.map(p => {
      if (p.id_instance !== id) return p;
      if (type === 'scale') return { ...p, scale: Math.max(0.2, p.scale + delta) };
      return { ...p, rotation: p.rotation + delta };
    }));
  };

  const saveProject = () => {
    const name = prompt("Project Name:", `Design ${savedPreviews.length + 1}`);
    if (name) {
      setSavedPreviews([...savedPreviews, { id: Date.now().toString(), name, items: [...placedPlants] }]);
    }
  };

  const removePlant = (id: number) => {
    setPlacedPlants(prev => prev.filter(p => p.id_instance !== id));
    if (activeInstance === id) setActiveInstance(null);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-1000">
      {/* Control Header */}
      <div className="flex flex-col md:flex-row justify-between items-center bg-white p-6 rounded-[3rem] shadow-xl border border-slate-100 gap-6">
        <div className="flex items-center gap-6">
          <div className="bg-slate-100 p-1.5 rounded-[2rem] flex">
            <button 
              onClick={() => setViewMode('blueprint')}
              className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all ${viewMode === 'blueprint' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              BLUEPRINT MODE
            </button>
            <button 
              onClick={() => setViewMode('spatial')}
              className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all ${viewMode === 'spatial' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              SPATIAL REALITY
            </button>
          </div>

          <div className="h-8 w-[1px] bg-slate-200 hidden md:block" />

          <div className="flex gap-2">
            {MOCK_PLANTS.map(p => (
              <button
                key={p.id}
                onClick={() => setSelectedPlant(p)}
                className={`w-12 h-12 rounded-xl border-2 transition-all p-1 bg-white ${selectedPlant.id === p.id ? 'border-emerald-500 scale-110 shadow-lg' : 'border-slate-100 opacity-40'}`}
              >
                <img src={p.imageUrl} className="w-full h-full object-cover rounded-lg" />
              </button>
            ))}
          </div>
        </div>

        <div className="flex gap-3">
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-[10px] tracking-widest hover:bg-emerald-600 transition-all uppercase"
          >
            Upload Photo
          </button>
          <button 
            onClick={saveProject}
            className="px-6 py-3 bg-emerald-100 text-emerald-700 rounded-2xl font-black text-[10px] tracking-widest hover:bg-emerald-200 transition-all uppercase"
          >
            Save Preview
          </button>
          <input type="file" ref={fileInputRef} hidden accept="image/*" onChange={handleFileUpload} />
        </div>
      </div>

      <div className="grid lg:grid-cols-4 gap-8">
        {/* Main Canvas Area */}
        <div 
          ref={containerRef}
          onClick={addPlantToScene}
          className="lg:col-span-3 relative h-[65vh] rounded-[4rem] overflow-hidden border-[12px] border-white shadow-2xl bg-slate-200 group"
        >
          {viewMode === 'spatial' ? (
            <CameraView 
              isActive={true} 
              overlayContent={
                <div className="absolute inset-0 pointer-events-none">
                  <SceneOverlay items={placedPlants} activeId={activeInstance} onUpdate={updatePlant} onRemove={removePlant} onSelect={setActiveInstance} />
                </div>
              }
            />
          ) : (
            <div className="w-full h-full flex items-center justify-center relative">
              {uploadedBg ? (
                <img src={uploadedBg} className="w-full h-full object-cover" />
              ) : (
                <div className="text-center opacity-30">
                  <i className="fas fa-image text-6xl mb-4" />
                  <p className="font-black text-sm uppercase tracking-widest">Upload your room photo to start</p>
                </div>
              )}
              <div className="absolute inset-0 pointer-events-none">
                <SceneOverlay items={placedPlants} activeId={activeInstance} onUpdate={updatePlant} onRemove={removePlant} onSelect={setActiveInstance} />
              </div>
            </div>
          )}

          {/* HUD Feedback */}
          <div className="absolute top-8 left-8 flex flex-col gap-3 pointer-events-none">
            <div className="glass-card px-6 py-3 rounded-full border border-white/50 shadow-xl flex items-center gap-3">
              <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse" />
              <span className="text-[10px] font-black text-slate-800 tracking-widest uppercase">
                {viewMode === 'spatial' ? 'Live AR Environment' : 'Blueprint Calibration'}
              </span>
            </div>
          </div>
        </div>

        {/* Workspace Sidebar */}
        <div className="space-y-6">
          <div className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm h-full flex flex-col">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6 flex items-center gap-2">
              <i className="fas fa-layer-group text-emerald-500" />
              Project Assets
            </h3>

            <div className="flex-1 overflow-y-auto space-y-4 no-scrollbar min-h-[200px]">
              {placedPlants.length === 0 ? (
                <div className="text-center py-10 opacity-20">
                  <p className="text-[10px] font-black uppercase tracking-tighter">No plants placed yet</p>
                </div>
              ) : (
                placedPlants.map(p => (
                  <div 
                    key={p.id_instance}
                    onMouseEnter={() => setActiveInstance(p.id_instance)}
                    className={`p-4 rounded-2xl border-2 transition-all flex items-center justify-between group cursor-pointer ${activeInstance === p.id_instance ? 'border-emerald-500 bg-emerald-50' : 'border-slate-50 bg-slate-50'}`}
                  >
                    <div className="flex items-center gap-3">
                      <img src={p.imageUrl} className="w-10 h-10 rounded-lg object-cover" />
                      <div>
                        <p className="text-[11px] font-black text-slate-800 uppercase">{p.name}</p>
                        <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Scale: {p.scale.toFixed(1)}x</p>
                      </div>
                    </div>
                    <button onClick={() => removePlant(p.id_instance)} className="text-slate-300 hover:text-red-500 transition-colors">
                      <i className="fas fa-trash-alt text-xs" />
                    </button>
                  </div>
                ))
              )}
            </div>

            <div className="mt-6 pt-6 border-t border-slate-100">
               <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Saved Scenarios</h4>
               <div className="space-y-2">
                 {savedPreviews.map(proj => (
                    <button 
                      key={proj.id} 
                      onClick={() => setPlacedPlants(proj.items)}
                      className="w-full text-left p-3 rounded-xl bg-slate-50 hover:bg-slate-100 text-[10px] font-black uppercase flex justify-between items-center group"
                    >
                      {proj.name}
                      <i className="fas fa-chevron-right opacity-0 group-hover:opacity-100" />
                    </button>
                 ))}
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

interface SceneOverlayProps {
  items: PlacedPlant[];
  activeId: number | null;
  onUpdate: (id: number, type: 'scale' | 'rotate', delta: number) => void;
  onRemove: (id: number) => void;
  onSelect: (id: number) => void;
}

const SceneOverlay: React.FC<SceneOverlayProps> = ({ items, activeId, onUpdate, onRemove, onSelect }) => {
  return (
    <>
      {items.map((p) => (
        <div
          key={p.id_instance}
          className="absolute pointer-events-auto group/asset"
          style={{
            left: `${p.x}%`,
            top: `${p.y}%`,
            transform: `translate(-50%, -100%) scale(${p.scale}) rotate(${p.rotation}deg)`,
            zIndex: Math.floor(p.y),
          }}
          onMouseDown={() => onSelect(p.id_instance)}
        >
          <div className="relative">
            <img 
              src={p.imageUrl} 
              alt={p.name} 
              className={`w-48 h-64 object-contain transition-all duration-500 ${activeId === p.id_instance ? 'brightness-110 drop-shadow-2xl' : 'brightness-100'}`}
              style={{ 
                mixBlendMode: 'multiply',
                filter: 'brightness(1.1) contrast(1.1) saturate(1.1)',
                WebkitMaskImage: 'radial-gradient(circle at center, black 68%, transparent 100%)',
              }}
            />
            {/* Environmental Projection Shadow */}
            <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-3/4 h-5 bg-black/30 blur-2xl rounded-full scale-y-[0.2] -z-10 mix-blend-multiply" />
          </div>

          {/* Active Controls */}
          <div className={`absolute -top-16 left-1/2 -translate-x-1/2 flex bg-slate-900/90 backdrop-blur-md text-white rounded-2xl p-1.5 gap-3 border border-white/20 px-5 shadow-2xl transition-all ${activeId === p.id_instance ? 'scale-100 opacity-100' : 'scale-75 opacity-0'}`}>
            <button onMouseDown={(e) => { e.stopPropagation(); onUpdate(p.id_instance, 'scale', 0.1); }} className="hover:text-emerald-400"><i className="fas fa-plus" /></button>
            <button onMouseDown={(e) => { e.stopPropagation(); onUpdate(p.id_instance, 'scale', -0.1); }} className="hover:text-emerald-400"><i className="fas fa-minus" /></button>
            <div className="w-[1px] bg-white/20 mx-1" />
            <button onMouseDown={(e) => { e.stopPropagation(); onUpdate(p.id_instance, 'rotate', 15); }} className="hover:text-emerald-400"><i className="fas fa-redo" /></button>
            <button onMouseDown={(e) => { e.stopPropagation(); onRemove(p.id_instance); }} className="hover:text-red-400 ml-1"><i className="fas fa-times" /></button>
          </div>
        </div>
      ))}
    </>
  );
};

import React, { useState, useMemo } from 'react';
import { Plant, PlantCategory } from '../types';
import { PlantCard } from './PlantCard';

interface ShopProps {
  plants: Plant[];
  onAddToCart: (plant: Plant) => void;
  onPreview: (plant: Plant) => void;
  userWishlist: string[];
  onToggleWishlist: (id: string) => void;
}

export const Shop: React.FC<ShopProps> = ({ plants, onAddToCart, onPreview, userWishlist, onToggleWishlist }) => {
  const [activeCategory, setActiveCategory] = useState<PlantCategory | 'All'>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedPlant, setSelectedPlant] = useState<Plant | null>(null);

  const filteredPlants = useMemo(() => {
    return plants.filter(p => {
      const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [plants, activeCategory, searchQuery]);

  return (
    <div className="space-y-10 animate-in fade-in duration-700">
      {/* Search & Category Filter */}
      <div className="flex flex-col md:flex-row gap-6 items-center justify-between">
        <div className="relative w-full md:max-w-md group">
          <i className="fas fa-search absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-emerald-500 transition-colors" />
          <input 
            type="text" 
            placeholder="Search flora by name..." 
            className="w-full pl-14 pr-6 py-4 bg-white rounded-2xl border border-slate-100 shadow-sm focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-slate-800 transition-all"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>

        <div className="flex bg-slate-100 p-1.5 rounded-[2rem] overflow-x-auto no-scrollbar max-w-full">
          {['All', ...Object.values(PlantCategory)].map((cat) => (
            <button 
              key={cat}
              onClick={() => setActiveCategory(cat as any)}
              className={`px-8 py-2.5 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all whitespace-nowrap ${activeCategory === cat ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600 uppercase'}`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Stats bar */}
      <div className="flex gap-4 items-center">
        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{filteredPlants.length} Varieties Found</span>
        <div className="h-[1px] flex-1 bg-slate-100" />
      </div>

      {/* Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-8">
        {filteredPlants.map(p => (
          <div key={p.id} onClick={() => setSelectedPlant(p)} className="cursor-pointer">
            <PlantCard 
              plant={p} 
              onAddToCart={(plant) => { onAddToCart(plant); }} 
              onPreview={onPreview}
              isWishlisted={userWishlist.includes(p.id)}
              onToggleWishlist={onToggleWishlist}
            />
          </div>
        ))}
      </div>

      {/* Detail Modal */}
      {selectedPlant && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-xl" onClick={() => setSelectedPlant(null)} />
          <div className="relative w-full max-w-5xl bg-white rounded-[4rem] overflow-hidden shadow-2xl flex flex-col md:flex-row animate-in zoom-in-95 duration-500">
            <div className="md:w-1/2 h-[400px] md:h-auto">
              <img src={selectedPlant.imageUrl} className="w-full h-full object-cover" alt={selectedPlant.name} />
            </div>
            <div className="md:w-1/2 p-12 space-y-8 overflow-y-auto no-scrollbar">
              <div className="flex justify-between items-start">
                <div>
                  <p className="text-emerald-600 font-black text-xs uppercase tracking-widest mb-2">{selectedPlant.category}</p>
                  <h2 className="text-4xl font-black text-slate-800 tracking-tighter">{selectedPlant.name}</h2>
                </div>
                <button onClick={() => setSelectedPlant(null)} className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-slate-400 hover:text-red-500 transition-colors">
                  <i className="fas fa-times" />
                </button>
              </div>

              <div className="flex items-end gap-2">
                <span className="text-3xl font-black text-slate-900">Rs. {selectedPlant.price.toLocaleString()}</span>
                <span className="text-slate-400 text-sm font-bold pb-1 line-through">Rs. {(selectedPlant.price * 1.2).toLocaleString()}</span>
              </div>

              <div className="grid grid-cols-3 gap-4">
                <div className="bg-slate-50 p-4 rounded-3xl text-center">
                  <i className="fas fa-sun text-amber-500 mb-2" />
                  <p className="text-[10px] font-black uppercase text-slate-400">Sunlight</p>
                  <p className="text-xs font-bold text-slate-800">{selectedPlant.sunlight}</p>
                </div>
                <div className="bg-slate-50 p-4 rounded-3xl text-center">
                  <i className="fas fa-tint text-blue-500 mb-2" />
                  <p className="text-[10px] font-black uppercase text-slate-400">Water</p>
                  <p className="text-xs font-bold text-slate-800">{selectedPlant.watering}</p>
                </div>
                <div className="bg-slate-50 p-4 rounded-3xl text-center">
                  <i className="fas fa-mountain text-emerald-500 mb-2" />
                  <p className="text-[10px] font-black uppercase text-slate-400">Soil</p>
                  <p className="text-xs font-bold text-slate-800">{selectedPlant.soil}</p>
                </div>
              </div>

              <div className="space-y-4">
                <h4 className="text-xs font-black uppercase tracking-widest text-slate-400">Growth Information</h4>
                <div className="flex gap-3">
                  <span className="px-4 py-2 bg-slate-100 rounded-xl text-xs font-bold">Size: {selectedPlant.size}</span>
                  <span className="px-4 py-2 bg-slate-100 rounded-xl text-xs font-bold">Stage: {selectedPlant.growthStage}</span>
                  <span className="px-4 py-2 bg-emerald-50 text-emerald-700 rounded-xl text-xs font-bold">Care: {selectedPlant.maintenanceLevel}</span>
                </div>
                <p className="text-slate-600 text-sm leading-relaxed">{selectedPlant.description}</p>
              </div>

              <div className="flex gap-4 pt-4">
                <button 
                  onClick={() => { onAddToCart(selectedPlant); setSelectedPlant(null); }}
                  className="flex-1 bg-slate-900 text-white py-5 rounded-[2rem] font-black text-sm tracking-widest hover:bg-emerald-600 transition-all shadow-xl shadow-slate-200"
                >
                  ADD TO CART
                </button>
                <button 
                  onClick={() => { onPreview(selectedPlant); setSelectedPlant(null); }}
                  className="w-20 bg-emerald-50 text-emerald-600 rounded-[2rem] flex items-center justify-center hover:bg-emerald-100 transition-colors border border-emerald-100 shadow-lg"
                >
                  <i className="fas fa-eye text-xl" />
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { MOCK_PLANTS } from './constants';
import { Plant, CartItem, UserRole, User } from './types';
import { Shop } from './components/Shop';
import { ARVisualizer } from './components/ARVisualizer';
import { DiseaseScanner } from './components/DiseaseScanner';
import { AdminPanel } from './components/AdminPanel';
import { LandscapeDesigner } from './components/LandscapeDesigner';
import { Auth } from './components/Auth';

type Tab = 'shop' | 'visualize' | 'doctor' | 'admin' | 'landscape' | 'history' | 'auth' | 'admin-login' | 'onboarding' | 'wishlist';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('shop');
  const [plants, setPlants] = useState<Plant[]>(MOCK_PLANTS.map(p => ({ ...p, stock: 10, maintenanceLevel: 'Easy', previewCount: Math.floor(Math.random() * 100) })));
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [deliveryMethod, setDeliveryMethod] = useState<'pickup' | 'express'>('pickup');
  const [hasOnboarded, setHasOnboarded] = useState(false);

  useEffect(() => {
    if (!hasOnboarded && activeTab === 'shop') {
      const timer = setTimeout(() => setActiveTab('onboarding'), 1000);
      return () => clearTimeout(timer);
    }
  }, [hasOnboarded]);

  const addToCart = (plant: Plant) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === plant.id);
      if (existing) {
        return prev.map(item => item.id === plant.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...plant, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const handleAuthRequired = (targetTab: Tab) => {
    if (!user) {
      setActiveTab('auth');
    } else {
      setActiveTab(targetTab);
    }
  };

  const toggleWishlist = (id: string) => {
    if (!user) {
      setActiveTab('auth');
      return;
    }
    const isWished = user.wishlist.includes(id);
    const newWishlist = isWished 
      ? user.wishlist.filter(wId => wId !== id)
      : [...user.wishlist, id];
    setUser({ ...user, wishlist: newWishlist });
  };

  const total = useMemo(() => {
    const subtotal = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);
    return subtotal + (deliveryMethod === 'express' ? 1500 : 0);
  }, [cart, deliveryMethod]);

  if (activeTab === 'onboarding') {
    return (
      <div className="fixed inset-0 z-[200] bg-emerald-950 flex items-center justify-center p-6">
        <div className="max-w-xl text-center space-y-8 animate-in zoom-in-95 duration-700">
          <div className="w-24 h-24 bg-emerald-500 rounded-[2.5rem] flex items-center justify-center mx-auto shadow-2xl shadow-emerald-500/50">
            <i className="fas fa-seedling text-white text-4xl" />
          </div>
          <h1 className="text-5xl font-black text-white tracking-tighter">Grow Smarter.</h1>
          <p className="text-emerald-100/60 text-lg font-medium leading-relaxed">
            Welcome to FloraVision Pakistan. Discover plants, design your garden in AR, and use AI to keep your foliage healthy. 
          </p>
          <button 
            onClick={() => { setHasOnboarded(true); setActiveTab('shop'); }}
            className="bg-white text-emerald-900 px-12 py-5 rounded-[2rem] font-black text-lg hover:scale-105 transition-all"
          >
            EXPLORE GARDEN
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pb-24 lg:pb-0 bg-slate-50/50">
      <nav className="fixed bottom-0 left-0 right-0 z-50 bg-white/90 backdrop-blur-2xl border-t border-slate-100 lg:top-0 lg:bottom-0 lg:w-24 lg:border-r lg:border-t-0 flex lg:flex-col justify-around lg:justify-center items-center py-6">
        {[
          { id: 'shop', icon: 'fa-leaf', label: 'GARDEN' },
          { id: 'landscape', icon: 'fa-pencil-ruler', label: 'DESIGN' },
          { id: 'doctor', icon: 'fa-stethoscope', label: 'DOCTOR' },
          { id: 'wishlist', icon: 'fa-heart', label: 'SAVED' },
          { id: 'history', icon: 'fa-truck', label: 'ORDERS' }
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => (item.id !== 'shop' && item.id !== 'landscape' ? handleAuthRequired(item.id as Tab) : setActiveTab(item.id as Tab))} 
            className={`flex flex-col items-center gap-1 transition-all ${activeTab === item.id ? 'text-emerald-600 scale-110' : 'text-slate-300 hover:text-slate-400'}`}
          >
            <i className={`fas ${item.icon} text-2xl`} />
            <span className="text-[8px] font-black tracking-widest">{item.label}</span>
          </button>
        ))}
        {(user?.role === UserRole.BUSINESS_ADMIN || user?.role === UserRole.SUPER_ADMIN) && (
          <button onClick={() => setActiveTab('admin')} className={`mt-10 flex flex-col items-center gap-1 transition-all ${activeTab === 'admin' ? 'text-emerald-600' : 'text-slate-300'}`}>
            <i className="fas fa-chart-line text-2xl" />
            <span className="text-[8px] font-black tracking-widest">BIZ</span>
          </button>
        )}
      </nav>

      <main className="lg:ml-24">
        <header className="px-10 py-8 flex justify-between items-center bg-white/40 backdrop-blur-xl sticky top-0 z-40 border-b border-white/50">
          <div onClick={() => setActiveTab('shop')} className="cursor-pointer group flex items-center gap-4">
            <h1 className="text-3xl font-black text-slate-800 tracking-tighter group-hover:text-emerald-600 transition-colors">FLORAVISION</h1>
            <div className="h-8 w-[1px] bg-slate-200 hidden md:block" />
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] hidden md:block leading-tight">Smart Horticulture<br/>Platform • PKR</p>
          </div>

          <div className="flex items-center gap-6">
             {user ? (
               <div className="flex items-center gap-4 bg-white p-2 pr-6 rounded-full border border-slate-100">
                 <div className="w-10 h-10 bg-emerald-500 rounded-full flex items-center justify-center text-white font-black text-xs">
                   {user.email[0].toUpperCase()}
                 </div>
                 <div className="text-left">
                   <p className="text-[10px] font-black text-slate-400 uppercase leading-none">{user.role}</p>
                   <p className="text-xs font-bold text-slate-800 leading-tight">{user.email}</p>
                 </div>
                 <button onClick={() => { setUser(null); setActiveTab('shop'); }} className="ml-2 text-slate-300 hover:text-red-500 transition-colors">
                   <i className="fas fa-power-off" />
                 </button>
               </div>
             ) : (
               <div className="flex gap-2">
                 <button onClick={() => setActiveTab('auth')} className="bg-slate-900 text-white px-6 py-3 rounded-2xl font-black text-[10px] tracking-widest hover:bg-emerald-600 transition-all shadow-xl shadow-slate-900/10">
                   CLIENT LOGIN
                 </button>
                 <button onClick={() => setActiveTab('admin-login')} className="bg-white text-slate-900 border-2 border-slate-900 px-6 py-3 rounded-2xl font-black text-[10px] tracking-widest hover:bg-slate-50 transition-all">
                   ADMIN PORTAL
                 </button>
               </div>
             )}

             <button onClick={() => setIsCartOpen(true)} className="relative w-12 h-12 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center hover:scale-110 transition-transform">
               <i className="fas fa-shopping-bag text-lg" />
               {cart.length > 0 && <span className="absolute -top-1 -right-1 bg-emerald-500 text-white text-[10px] w-5 h-5 rounded-full border-2 border-white flex items-center justify-center font-black animate-bounce">{cart.length}</span>}
             </button>
          </div>
        </header>

        <div className="p-10 max-w-[1600px] mx-auto">
          {activeTab === 'auth' && <Auth onLogin={(u) => { setUser(u); setActiveTab('shop'); }} isAdminMode={false} />}
          {activeTab === 'admin-login' && <Auth onLogin={(u) => { setUser(u); setActiveTab('admin'); }} isAdminMode={true} />}

          {(activeTab === 'shop' || activeTab === 'wishlist') && (
            <Shop 
              plants={activeTab === 'wishlist' && user ? plants.filter(p => user.wishlist.includes(p.id)) : plants} 
              onAddToCart={addToCart} 
              onPreview={(p) => {
                setPlants(prev => prev.map(item => item.id === p.id ? {...item, previewCount: (item.previewCount||0)+1} : item));
                setActiveTab('landscape');
              }}
              userWishlist={user?.wishlist || []}
              onToggleWishlist={toggleWishlist}
            />
          )}
          {activeTab === 'landscape' && <LandscapeDesigner />}
          {activeTab === 'doctor' && <DiseaseScanner />}
          {activeTab === 'admin' && user && (
            <AdminPanel 
              plants={plants} 
              userRole={user.role}
              onAdd={(p) => setPlants([...plants, p])} 
              onRemove={(id) => setPlants(plants.filter(p => p.id !== id))} 
              onUpdateStock={(id, stock) => setPlants(plants.map(p => p.id === id ? {...p, stock} : p))}
            />
          )}
          {activeTab === 'history' && user && (
            <div className="max-w-4xl mx-auto space-y-10">
              <div className="bg-white p-12 rounded-[3.5rem] shadow-sm border border-slate-100 flex items-center gap-10">
                <div className="w-20 h-20 bg-blue-50 text-blue-600 rounded-3xl flex items-center justify-center text-3xl">
                  <i className="fas fa-box-open" />
                </div>
                <div>
                  <h2 className="text-3xl font-black text-slate-800">Track Shipments</h2>
                  <p className="text-slate-400 font-medium">Real-time logistics data for your active orders.</p>
                </div>
              </div>
              {user.history.map(order => (
                <div key={order.id} className="bg-white p-10 rounded-[3rem] shadow-sm border border-slate-100">
                   <div className="flex justify-between items-center mb-8">
                     <div>
                       <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{order.date}</p>
                       <h4 className="text-xl font-black text-slate-800">Order #{order.id}</h4>
                     </div>
                     <span className="px-4 py-1 bg-emerald-100 text-emerald-700 rounded-full text-[10px] font-black">{order.status}</span>
                   </div>
                   <div className="relative h-2 bg-slate-50 rounded-full overflow-hidden mb-6">
                     <div className="absolute top-0 left-0 h-full bg-emerald-500 w-3/4" />
                   </div>
                   <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-widest">
                     <span>Warehouse</span>
                     <span>In Transit</span>
                     <span className="text-emerald-500">Arrived</span>
                   </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      {isCartOpen && (
        <div className="fixed inset-0 z-[200] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-xl" onClick={() => setIsCartOpen(false)} />
          <div className="relative w-full max-w-lg bg-white h-full shadow-2xl p-12 flex flex-col animate-in slide-in-from-right duration-500 border-l border-white/20">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-4xl font-black text-slate-800 tracking-tighter">Your Bag</h2>
              <button onClick={() => setIsCartOpen(false)} className="w-10 h-10 bg-slate-50 rounded-full flex items-center justify-center text-slate-400 hover:text-slate-800">
                <i className="fas fa-times" />
