import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface AuthProps {
  onLogin: (user: User) => void;
  isAdminMode?: boolean;
}

export const Auth: React.FC<AuthProps> = ({ onLogin, isAdminMode = false }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Role Logic Simulation
    let role = UserRole.CUSTOMER;
    if (isAdminMode) {
      if (email.includes('super')) role = UserRole.SUPER_ADMIN;
      else if (email.includes('admin')) role = UserRole.BUSINESS_ADMIN;
      else if (email.includes('staff')) role = UserRole.STAFF;
      else {
        setError("Invalid administrative credentials. Use provisioned staff or admin email.");
        return;
      }
    }

    const mockUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email,
      role: role,
      isSubscribed: email.includes('pro'),
      wishlist: [],
      history: []
    };
    onLogin(mockUser);
  };

  return (
    <div className="max-w-md mx-auto py-12 px-4 animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className={`bg-white rounded-[3rem] shadow-2xl overflow-hidden border-2 p-10 transition-all ${isAdminMode ? 'border-slate-800' : 'border-slate-100'}`}>
        <div className="text-center mb-10">
          <div className={`w-16 h-16 rounded-3xl flex items-center justify-center mx-auto text-2xl mb-6 transition-colors ${isAdminMode ? 'bg-slate-900 text-white' : 'bg-emerald-100 text-emerald-600'}`}>
            <i className={`fas ${isAdminMode ? 'fa-user-shield' : 'fa-user-circle'}`} />
          </div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">
            {isAdminMode ? 'Internal Portal' : (isLogin ? 'Welcome Back' : 'Join FloraVision')}
          </h2>
          <p className="text-slate-400 font-bold text-xs uppercase mt-2 tracking-widest">
            {isAdminMode ? 'Staff & Administration Login' : 'Experience the future of horticulture'}
          </p>

          {error && (
            <div className="mt-6 p-4 bg-red-50 text-red-600 rounded-2xl text-[10px] font-black uppercase tracking-wider animate-in shake-in">
              {error}
            </div>
          )}
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">Email Identity</label>
            <input 
              type="email" required placeholder={isAdminMode ? "staff.name@flora.com" : "customer@garden.com"}
              className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-emerald-500 rounded-2xl outline-none transition-all font-bold text-slate-800"
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-2 tracking-widest">Password</label>
            <input 
              type="password" required placeholder="••••••••"
              className="w-full p-4 bg-slate-50 border-2 border-transparent focus:border-emerald-500 rounded-2xl outline-none transition-all font-bold text-slate-800"
            />
          </div>

          <button type="submit" className={`w-full py-5 rounded-2xl font-black text-lg transition-all shadow-xl ${isAdminMode ? 'bg-slate-900 hover:bg-slate-800' : 'bg-emerald-600 hover:bg-emerald-500'} text-white`}>
            {isAdminMode ? 'AUTHORIZE' : (isLogin ? 'SIGN IN' : 'REGISTER')}
          </button>

          {!isAdminMode && (
            <button type="button" onClick={() => setIsLogin(!isLogin)} className="w-full text-center text-sm font-black text-emerald-600">
              {isLogin ? "New here? Sign Up" : "Back to Login"}
            </button>
          )}
        </form>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Plant, PlantCategory, UserRole, Order, User } from '../types';

interface AdminPanelProps {
  plants: Plant[];
  userRole: UserRole;
  onAdd: (plant: Plant) => void;
  onRemove: (id: string) => void;
  onUpdateStock: (id: string, newStock: number) => void;
  onUpdatePlant: (id: string, updatedData: Partial<Plant>) => void;
}

const MOCK_ORDERS: Order[] = [
  { id: 'ORD-001', date: '2024-05-20', items: ['Monstera'], total: 12500, status: 'Shipped', trackingNumber: 'FV-99210' },
  { id: 'ORD-002', date: '2024-05-21', items: ['Areca Palm', 'Boxwood'], total: 17500, status: 'Pending' },
];

export const AdminPanel: React.FC<AdminPanelProps> = ({ plants, userRole, onAdd, onRemove, onUpdateStock, onUpdatePlant }) => {
  const isStaff = userRole === UserRole.STAFF;
  const isAdmin = userRole === UserRole.BUSINESS_ADMIN || userRole === UserRole.SUPER_ADMIN;

  const [activeView, setActiveView] = useState<any>(isStaff ? 'inventory' : 'analytics');
  const [isAdding, setIsAdding] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [staffList, setStaffList] = useState<Partial<User>[]>([
    { id: 's1', email: 'staff.ali@flora.com', role: UserRole.STAFF }
  ]);

  const [formData, setFormData] = useState<Partial<Plant>>({
    name: '',
    price: 0,
    category: PlantCategory.INDOOR,
    stock: 0,
    imageUrl: 'https://images.unsplash.com/photo-1545239351-ef35f43d514b?auto=format&fit=crop&w=400',
    description: '',
    size: 'Medium',
    growthStage: 'Sapling'
  });

  const [newStaff, setNewStaff] = useState({ email: '', password: '' });

  // Load editing data into form
  useEffect(() => {
    if (editingId) {
      const plant = plants.find(p => p.id === editingId);
      if (plant) {
        setFormData(plant);
        setIsAdding(true);
      }
    } else {
      setFormData({
        name: '',
        price: 0,
        category: PlantCategory.INDOOR,
        stock: 0,
        imageUrl: 'https://images.unsplash.com/photo-1545239351-ef35f43d514b?auto=format&fit=crop&w=400',
        description: '',
        size: 'Medium',
        growthStage: 'Sapling'
      });
    }
  }, [editingId, plants]);

  const stats = useMemo(() => {
    const totalRev = plants.reduce((acc, p) => acc + (p.price * p.stock), 0);
    const lowStock = plants.filter(p => p.stock < 5).length;
    const mostPreviewed = [...plants].sort((a, b) => (b.previewCount || 0) - (a.previewCount || 0))[0];
    return { totalRev, lowStock, mostPreviewed };
  }, [plants]);

  const handleCreateStaff = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newStaff.email) return;
    setStaffList([...staffList, { id: Date.now().toString(), email: newStaff.email, role: UserRole.STAFF }]);
    setNewStaff({ email: '', password: '' });
    alert(`Staff Account Created: ${newStaff.email}.`);
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      onUpdatePlant(editingId, formData);
      alert("Asset Updated Successfully.");
    } else {
      onAdd({
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
        maintenanceLevel: 'Easy',
        previewCount: 0
      } as Plant);
      alert("New Asset Published to Catalog.");
