import React, { useState, useRef, useEffect, useMemo } from 'react';
import { CameraView } from './CameraView';
import { GARDEN_TOOLS } from '../constants';
import { LandscapeItem, Plant, Tool } from '../types';

type DesignMode = 'static' | 'live';
type Category = 'plants' | 'objects' | 'surfaces';

interface SavedDesign {
  id: string;
  name: string;
  items: LandscapeItem[];
  bgImage?: string;
}

interface LandscapeDesignerProps {
  initialItems?: LandscapeItem[];
  onItemsChange?: (items: LandscapeItem[]) => void;
  availablePlants: Plant[];
}

export const LandscapeDesigner: React.FC<LandscapeDesignerProps> = ({ 
  initialItems = [], 
  onItemsChange,
  availablePlants
}) => {
  const [items, setItems] = useState<LandscapeItem[]>(initialItems);
  const [history, setHistory] = useState<LandscapeItem[][]>([]);
  const [designMode, setDesignMode] = useState<DesignMode>('static');
  const [activeCategory, setActiveCategory] = useState<Category>('plants');
  const [selectedItemId, setSelectedItemId] = useState<string>(availablePlants[0]?.id || '');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [currentDesignName, setCurrentDesignName] = useState('New Concept');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    onItemsChange?.(items);
  }, [items]);

  useEffect(() => {
    if (initialItems.length !== items.length) {
      setItems(initialItems);
    }
  }, [initialItems]);

  const SURFACE_ASSETS = [
    { id: 's1', name: 'Premium Turf', imageUrl: 'https://images.unsplash.com/photo-1533460004989-cef01064af7c?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's2', name: 'Gravel Path', imageUrl: 'https://images.unsplash.com/photo-1508182314998-3bd49473002f?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's3', name: 'Paved Walkway', imageUrl: 'https://images.unsplash.com/photo-1590059392253-df2676f4e183?auto=format&fit=crop&w=400', type: 'surface' }
  ];

  const currentPalette = useMemo(() => {
    if (activeCategory === 'plants') return availablePlants;
    if (activeCategory === 'objects') return GARDEN_TOOLS;
    return SURFACE_ASSETS;
  }, [activeCategory, availablePlants]);

  const getItemData = (itemId: string) => {
    return [...availablePlants, ...GARDEN_TOOLS, ...SURFACE_ASSETS].find(x => x.id === itemId);
  };

  const proximityAlerts = useMemo(() => {
    const alerts: Record<string, boolean> = {};
    items.forEach((item, i) => {
      items.forEach((other, j) => {
        if (i === j) return;
        const dx = item.x - other.x;
        const dy = item.y - other.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        const itemData = getItemData(item.itemId);
        const category = (itemData as Plant)?.category || (itemData as Tool)?.category;
        const threshold = category === 'Tree' ? 14 : 8;

        if (distance < threshold) {
          alerts[item.instanceId] = true;
          alerts[other.instanceId] = true;
        }
      });
    });
    return alerts;
  }, [items, availablePlants]);

  const aiSuggestions = useMemo(() => {
    const itemCount = items.length;
    const overcrowded = Object.values(proximityAlerts).filter(v => v).length;
    const hasObjects = items.some(i => i.type === 'tool');

    if (overcrowded > 0) return "PROXIMITY ALERT: Some assets are clipping. Re-position benches or larger plants for better circulation.";
    if (itemCount === 0) return "Your canvas is empty. Start with hardscaping (benches/paths) or a focal tree.";
    if (!hasObjects && itemCount > 2) return "Aesthetic Tip: Add a Stone Fountain or Bench to create a human-centered focal point.";
    return "Composition Harmony: High. The balance between flora and artifacts is currently optimal.";
  }, [items, proximityAlerts]);

  const addItem = (e: React.MouseEvent<HTMLDivElement>) => {
    if (designMode === 'static' && !uploadedImage && !e.shiftKey) return;
    if (!selectedItemId) return;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newItem: LandscapeItem = {
      instanceId: Math.random().toString(36).substr(2, 9),
      itemId: selectedItemId,
      type: activeCategory === 'plants' ? 'plant' : 'tool',
      x, y, rotation: 0, scale: activeCategory === 'surfaces' ? 2 : (activeCategory === 'objects' ? 0.8 : 1)
    };

    setHistory([...history, items]);
    setItems([...items, newItem]);
  };

  const handleUndo = () => {
    if (history.length > 0) {
      const prev = history[history.length - 1];
      setItems(prev);
      setHistory(history.slice(0, -1));
    }
  };

  const handleReset = () => {
    if (confirm("Clear all design layers?")) {
      setHistory([...history, items]);
      setItems([]);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (re) => setUploadedImage(re.target?.result as string);
      reader.readAsDataURL(file);
      setDesignMode('static');
    }
  };

  const saveDesign = () => {
    const newDesign: SavedDesign = {
      id: Date.now().toString(),
      name: currentDesignName,
      items: [...items],
      bgImage: uploadedImage || undefined
    };
    setSavedDesigns([...savedDesigns, newDesign]);
  };

  const loadDesign = (design: SavedDesign) => {
    setHistory([...history, items]);
    setItems(design.items);
    if (design.bgImage) {
      setUploadedImage(design.bgImage);
      setDesignMode('static');
    } else {
      setDesignMode('live');
    }
    setCurrentDesignName(design.name);
  };

  const removeItem = (id: string) => {
    setHistory([...history, items]);
    setItems(items.filter(i => i.instanceId !== id));
  };

  const startARPreview = (id: string) => {
    setSelectedItemId(id);
    setDesignMode('live');
  };

  return (
    <div className="max-w-[1600px] mx-auto space-y-6 pb-12 animate-in fade-in duration-1000">
      <div className="flex flex-col md:flex-row justify-between items-center gap-6 bg-white p-6 rounded-[3rem] shadow-xl border border-slate-100">
        <div className="flex items-center gap-6">
          <div className="flex bg-slate-100 p-1.5 rounded-[2rem]">
            <button 
              onClick={() => setDesignMode('static')}
              className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all flex items-center gap-2 ${designMode === 'static' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-image" /> BLUEPRINT
            </button>
            <button 
              onClick={() => setDesignMode('live')}
              className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all flex items-center gap-2 ${designMode === 'live' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-video" /> LIVE AR
            </button>
          </div>

          <div className="flex gap-2">
            <button onClick={handleUndo} disabled={history.length === 0} className="w-10 h-10 bg-slate-100 text-slate-600 rounded-xl hover:bg-slate-200 disabled:opacity-30 transition-all flex items-center justify-center">
              <i className="fas fa-undo" />
            </button>
            <button onClick={handleReset} className="w-10 h-10 bg-slate-100 text-red-500 rounded-xl hover:bg-red-50 transition-all flex items-center justify-center">
              <i className="fas fa-trash-can" />
            </button>
          </div>
        </div>

        <div className="flex gap-3">
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl font-black text-[10px] tracking-widest hover:bg-slate-200 transition-all uppercase"
          >
            Upload Site
          </button>
          <button 
            onClick={saveDesign}
            className="bg-emerald-600 text-white px-8 py-3 rounded-2xl font-black text-[10px] tracking-widest hover:bg-emerald-700 transition-all uppercase shadow-lg"
          >
            Commit Design
          </button>
          <input ref={fileInputRef} type="file" hidden accept="image/*" onChange={handleFileUpload} />
        </div>
      </div>

      <div className="grid lg:grid-cols-4 gap-8">
        <div className="lg:col-span-3 relative h-[70vh] rounded-[4rem] overflow-hidden border-[12px] border-white shadow-2xl bg-slate-100">
          <div 
            ref={containerRef}
            onClick={addItem}
            className="w-full h-full relative cursor-crosshair"
          >
            {designMode === 'live' ? (
              <CameraView 
                isActive={true} 
                overlayContent={
                  <div className="absolute inset-0 pointer-events-none">
                    <DesignerOverlay items={items} getItemData={getItemData} onRemove={removeItem} alerts={proximityAlerts} />
                  </div>
                }
              />
            ) : (
              <div className="w-full h-full flex items-center justify-center bg-slate-200/50 relative">
                {uploadedImage ? (
                  <img src={uploadedImage} className="w-full h-full object-cover" />
                ) : (
                  <div className="text-center space-y-4 opacity-30">
                    <div className="w-20 h-20 bg-slate-300 rounded-full flex items-center justify-center mx-auto mb-4">
                      <i className="fas fa-camera text-3xl text-white" />
                    </div>
                    <p className="font-black text-sm uppercase tracking-widest">Awaiting Site Image</p>
                  </div>
                )}
                <div className="absolute inset-0 pointer-events-none">
                  <DesignerOverlay items={items} getItemData={getItemData} onRemove={removeItem} alerts={proximityAlerts} />
                </div>
              </div>
            )}
          </div>

          <div className="absolute top-8 right-8 pointer-events-none">
             <div className={`glass-card p-6 rounded-[2.5rem] border transition-all max-w-xs shadow-2xl ${Object.keys(proximityAlerts).length > 0 ? 'border-red-500/50 bg-red-50/10' : 'border-white/40'}`}>
                <div className="flex items-center gap-3 mb-2">
                  <div className={`w-2 h-2 rounded-full animate-pulse ${Object.keys(proximityAlerts).length > 0 ? 'bg-red-500' : 'bg-emerald-500'}`} />
                  <p className={`text-[9px] font-black uppercase tracking-widest ${Object.keys(proximityAlerts).length > 0 ? 'text-red-600' : 'text-emerald-700'}`}>
                    AI Spatial Audit
                  </p>
                </div>
                <p className="text-xs font-bold text-slate-800 leading-relaxed italic">"{aiSuggestions}"</p>
             </div>
          </div>

          <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-slate-900/90 backdrop-blur-xl p-2 rounded-[2.5rem] shadow-2xl border border-white/10">
            {[
              { id: 'plants', icon: 'fa-seedling', label: 'Flora' },
              { id: 'objects', icon: 'fa-chair', label: 'Artifacts' },
              { id: 'surfaces', icon: 'fa-mountain', label: 'Surfaces' }
            ].map(cat => (
              <button 
                key={cat.id}
                onClick={() => setActiveCategory(cat.id as Category)}
                className={`px-6 py-3 rounded-full font-black text-[9px] tracking-widest uppercase transition-all flex items-center gap-2 ${activeCategory === cat.id ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
              >
                <i className={`fas ${cat.icon}`} />
                {cat.label}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-8 h-[70vh] flex flex-col">
          <div className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm flex-1 overflow-hidden flex flex-col">
            <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6 flex items-center gap-3">
              <i className={`fas ${activeCategory === 'plants' ? 'fa-leaf' : activeCategory === 'objects' ? 'fa-fountain' : 'fa-th-large'} text-emerald-600`} />
              Project Library
            </h4>
            <div className="flex-1 overflow-y-auto pr-2 space-y-4 no-scrollbar">
              {currentPalette.map((p: any) => (
                <div 
                  key={p.id}
                  className={`w-full group flex items-center gap-4 p-4 rounded-3xl border-2 transition-all ${selectedItemId === p.id ? 'bg-emerald-50 border-emerald-500 shadow-sm' : 'bg-white border-transparent hover:border-slate-50'}`}
                >
                  <button onClick={() => setSelectedItemId(p.id)} className="flex-1 flex items-center gap-4 text-left">
                    <div className="w-14 h-14 rounded-2xl overflow-hidden bg-slate-50 border border-slate-100 flex items-center justify-center p-1">
                      <img src={p.imageUrl} className="w-full h-full object-contain" />
                    </div>
                    <div>
                      <p className={`text-[11px] font-black uppercase tracking-tight ${selectedItemId === p.id ? 'text-emerald-700' : 'text-slate-800'}`}>{p.name}</p>
                      <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">{p.category || 'Environmental Asset'}</p>
                    </div>
                  </button>
                  <button 
                    onClick={(e) => { e.stopPropagation(); startARPreview(p.id); }}
                    className="w-10 h-10 bg-emerald-100 text-emerald-600 rounded-xl flex items-center justify-center hover:bg-emerald-500 hover:text-white transition-all shadow-sm"
                    title="Live AR Preview"
                  >
                    <i className="fas fa-eye text-xs" />
                  </button>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-slate-900 p-8 rounded-[3.5rem] shadow-2xl text-white">
             <div className="flex justify-between items-center mb-4">
                <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400">Archived Designs</h4>
                <span className="text-[10px] font-black bg-white/10 px-2 py-0.5 rounded-md">{savedDesigns.length}</span>
             </div>
            <div className="space-y-3 max-h-48 overflow-y-auto no-scrollbar">
              {savedDesigns.length === 0 ? (
                <div className="text-center py-6 border-2 border-dashed border-white/5 rounded-3xl">
                  <p className="text-[10px] text-slate-500 font-bold uppercase">No saved concepts</p>
                </div>
              ) : (
                savedDesigns.map(d => (
                  <button 
                    key={d.id} 
                    onClick={() => loadDesign(d)}
                    className="w-full flex justify-between items-center p-4 bg-white/5 rounded-2xl hover:bg-white/10 transition-colors border border-transparent hover:border-white/10"
                  >
                    <div className="flex flex-col items-start">
                      <span className="text-xs font-black">{d.name}</span>
                      <span className="text-[9px] text-slate-500 font-bold">{d.items.length} layers</span>
                    </div>
                    <i className="fas fa-arrow-right text-[10px] text-slate-500" />
                  </button>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

interface DesignerOverlayProps {
  items: LandscapeItem[];
  getItemData: (itemId: string) => any;
  onRemove: (id: string) => void;
  alerts: Record<string, boolean>;
}

const DesignerOverlay: React.FC<DesignerOverlayProps> = ({ items, getItemData, onRemove, alerts }) => {
  return (
    <>
      {items.map((item) => {
        const data = getItemData(item.itemId);
        const isSurface = item.itemId.startsWith('s');
        const isArtifact = item.type === 'tool';
        const hasAlert = alerts[item.instanceId];

        return (
          <div
            key={item.instanceId}
            className="absolute pointer-events-auto group/item animate-in zoom-in-75 duration-300"
            style={{
              left: `${item.x}%`,
              top: `${item.y}%`,
              transform: `translate(-50%, -100%) scale(${item.scale})`,
              zIndex: isSurface ? 1 : Math.floor(item.y)
            }}
          >
            <div className="relative">
              {hasAlert && (
                <div className="absolute inset-0 -m-4 border-2 border-red-500/30 rounded-full animate-pulse blur-md" />
              )}

              <div className="relative group/asset">
                 <img 
                  src={data?.imageUrl} 
                  className={`
                    ${isSurface ? 'w-80 h-60 rounded-[3rem] object-cover mix-blend-multiply opacity-80' : 
                      isArtifact ? 'w-32 h-32 object-contain drop-shadow-xl' : 
                      'w-56 h-72 object-contain'} 
                    transition-all duration-500
                  `}
                  style={{ 
                    filter: `brightness(1.05) contrast(${isSurface ? 0.8 : 1.1})`,
                    WebkitMaskImage: !isSurface ? 'radial-gradient(circle at center, black 80%, transparent 100%)' : 'none',
                  }}
                />

                {isArtifact && (
                  <div className="absolute inset-0 bg-emerald-400/10 opacity-0 group-hover/asset:opacity-100 rounded-full blur-xl transition-opacity pointer-events-none" />
                )}
              </div>

              {!isSurface && (
                <div className="absolute -bottom-4 left-1/2 -translate-x-1/2 w-[90%] h-4 bg-black/40 blur-3xl rounded-full scale-y-[0.25] -z-10 mix-blend-multiply" />
              )}
            </div>

            <div className="absolute -top-14 left-1/2 -translate-x-1/2 opacity-0 group-hover/item:opacity-100 flex gap-2 bg-slate-900/95 backdrop-blur-md p-2 rounded-2xl shadow-2xl transition-all scale-90 border border-white/10">
              <div className="px-3 py-1 border-r border-white/10 flex flex-col justify-center">
                 <p className="text-[8px] font-black text-white/40 uppercase tracking-widest leading-none mb-1">Asset</p>
                 <p className="text-[10px] font-black text-white truncate max-w-[80px] leading-none">{data?.name}</p>
              </div>
              <button 
                 onClick={(e) => { e.stopPropagation(); onRemove(item.instanceId); }}
                 className="bg-red-500/20 text-red-400 w-10 h-10 rounded-xl flex items-center justify-center hover:bg-red-500 hover:text-white transition-all shadow-inner"
              >
                <i className="fas fa-trash-alt text-xs" />
              </button>
            </div>
          </div>
        );
      })}
    </>
  );
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { CameraView } from './CameraView';
import { GARDEN_TOOLS } from '../constants';
import { LandscapeItem, Plant, Tool } from '../types';

type DesignMode = 'static' | 'live';
type Category = 'plants' | 'objects' | 'surfaces';

interface SavedDesign {
  id: string;
  name: string;
  items: LandscapeItem[];
  bgImage?: string;
  timestamp: number;
}

interface LandscapeDesignerProps {
  initialItems?: LandscapeItem[];
  onItemsChange?: (items: LandscapeItem[]) => void;
  availablePlants: Plant[];
}

export const LandscapeDesigner: React.FC<LandscapeDesignerProps> = ({ 
  initialItems = [], 
  onItemsChange,
  availablePlants
}) => {
  const [items, setItems] = useState<LandscapeItem[]>(initialItems);
  const [history, setHistory] = useState<LandscapeItem[][]>([]);
  const [designMode, setDesignMode] = useState<DesignMode>('static');
  const [activeCategory, setActiveCategory] = useState<Category>('plants');
  const [selectedItemId, setSelectedItemId] = useState<string>(availablePlants[0]?.id || '');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [currentDesignName, setCurrentDesignName] = useState('Garden Concept Alpha');
  const [compareList, setCompareList] = useState<string[]>([]);
  const [isComparing, setIsComparing] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    onItemsChange?.(items);
  }, [items]);

  useEffect(() => {
    if (initialItems.length !== items.length) {
      setItems(initialItems);
    }
  }, [initialItems]);

  const SURFACE_ASSETS = [
    { id: 's1', name: 'Premium Turf', imageUrl: 'https://images.unsplash.com/photo-1533460004989-cef01064af7c?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's2', name: 'Gravel Path', imageUrl: 'https://images.unsplash.com/photo-1508182314998-3bd49473002f?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's3', name: 'Paved Walkway', imageUrl: 'https://images.unsplash.com/photo-1590059392253-df2676f4e183?auto=format&fit=crop&w=400', type: 'surface' }
  ];

  const currentPalette = useMemo(() => {
    if (activeCategory === 'plants') return availablePlants;
    if (activeCategory === 'objects') return GARDEN_TOOLS;
    return SURFACE_ASSETS;
  }, [activeCategory, availablePlants]);

  const getItemData = (itemId: string) => {
    return [...availablePlants, ...GARDEN_TOOLS, ...SURFACE_ASSETS].find(x => x.id === itemId);
  };

  const proximityAlerts = useMemo(() => {
    const alerts: Record<string, boolean> = {};
    items.forEach((item, i) => {
      items.forEach((other, j) => {
        if (i === j) return;
        const dx = item.x - other.x;
        const dy = item.y - other.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        const itemData = getItemData(item.itemId);
        const category = (itemData as Plant)?.category || (itemData as Tool)?.category;
        const threshold = category === 'Tree' ? 14 : 8;

        if (distance < threshold) {
          alerts[item.instanceId] = true;
          alerts[other.instanceId] = true;
        }
      });
    });
    return alerts;
  }, [items, availablePlants]);

  const aiSuggestions = useMemo(() => {
    const itemCount = items.length;
    const overcrowded = Object.values(proximityAlerts).filter(v => v).length;
    const hasObjects = items.some(i => i.type === 'tool');

    if (overcrowded > 0) return "PROXIMITY ALERT: Some assets are clipping. Re-position benches or larger plants for better circulation.";
    if (itemCount === 0) return "Your canvas is empty. Start with hardscaping (benches/paths) or a focal tree.";
    if (!hasObjects && itemCount > 2) return "Aesthetic Tip: Add a Stone Fountain or Bench to create a human-centered focal point.";
    return "Composition Harmony: High. The balance between flora and artifacts is currently optimal.";
  }, [items, proximityAlerts]);

  const addItem = (e: React.MouseEvent<HTMLDivElement>) => {
    if (designMode === 'static' && !uploadedImage && !e.shiftKey) return;
    if (!selectedItemId) return;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newItem: LandscapeItem = {
      instanceId: Math.random().toString(36).substr(2, 9),
      itemId: selectedItemId,
      type: activeCategory === 'plants' ? 'plant' : 'tool',
      x, y, rotation: 0, scale: activeCategory === 'surfaces' ? 2 : (activeCategory === 'objects' ? 0.8 : 1)
    };

    setHistory([...history, items]);
    setItems([...items, newItem]);
  };

  const saveDesign = () => {
    const name = prompt("Enter a name for this variation:", currentDesignName) || `Variation ${savedDesigns.length + 1}`;
    const newDesign: SavedDesign = {
      id: Date.now().toString(),
      name,
      items: [...items],
      bgImage: uploadedImage || undefined,
      timestamp: Date.now()
    };
    setSavedDesigns(prev => [newDesign, ...prev]);
    setCurrentDesignName(name);
  };

  const loadDesign = (design: SavedDesign) => {
    setHistory([...history, items]);
    setItems(design.items);
    if (design.bgImage) {
      setUploadedImage(design.bgImage);
      setDesignMode('static');
    }
    setCurrentDesignName(design.name);
    setIsComparing(false);
  };

  const toggleCompare = (id: string) => {
    setCompareList(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id].slice(-4)
    );
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (re) => setUploadedImage(re.target?.result as string);
      reader.readAsDataURL(file);
      setDesignMode('static');
    }
  };

  return (
    <div className="max-w-[1600px] mx-auto space-y-6 pb-12 animate-in fade-in duration-1000">
      {/* Dynamic Header Controls */}
      <div className="flex flex-col md:flex-row justify-between items-center gap-6 bg-white p-6 rounded-[3rem] shadow-xl border border-slate-100">
        <div className="flex items-center gap-6">
          <div className="flex bg-slate-100 p-1.5 rounded-[2rem]">
            <button onClick={() => setDesignMode('static')} className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all ${designMode === 'static' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400'}`}>BLUEPRINT</button>
            <button onClick={() => setDesignMode('live')} className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all ${designMode === 'live' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400'}`}>LIVE AR</button>
          </div>

          <div className="flex gap-2">
            <button onClick={() => history.length > 0 && setItems(history[history.length-1])} disabled={history.length === 0} className="w-10 h-10 bg-slate-100 text-slate-600 rounded-xl disabled:opacity-30 flex items-center justify-center transition-all"><i className="fas fa-undo" /></button>
            <button onClick={() => setIsComparing(!isComparing)} className={`px-6 py-3 rounded-xl font-black text-[9px] tracking-widest uppercase transition-all flex items-center gap-2 ${isComparing ? 'bg-emerald-600 text-white' : 'bg-slate-100 text-slate-600'}`}>
              <i className="fas fa-columns" /> Compare {compareList.length > 0 && `(${compareList.length})`}
            </button>
          </div>
        </div>

        <div className="flex gap-3">
          <button onClick={() => fileInputRef.current?.click()} className="bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl font-black text-[10px] tracking-widest uppercase">Upload Site</button>
          <button onClick={saveDesign} className="bg-emerald-600 text-white px-8 py-3 rounded-2xl font-black text-[10px] tracking-widest uppercase shadow-lg">Save Version</button>
          <input ref={fileInputRef} type="file" hidden accept="image/*" onChange={handleFileUpload} />
        </div>
      </div>

      {isComparing ? (
        /* Side-by-Side Comparison Grid */
        <div className="animate-in zoom-in-95 duration-500">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-3xl font-black text-slate-800 tracking-tighter">Design Contrast Board</h2>
            <button onClick={() => setIsComparing(false)} className="text-slate-400 hover:text-slate-800 font-black text-xs uppercase tracking-widest flex items-center gap-2">
              <i className="fas fa-arrow-left" /> Back to Workspace
            </button>
          </div>

          <div className={`grid gap-6 ${compareList.length > 2 ? 'grid-cols-3' : compareList.length === 2 ? 'grid-cols-2' : 'grid-cols-1'}`}>
            {compareList.map(id => {
              const design = savedDesigns.find(d => d.id === id);
              if (!design) return null;
              return (
                <div key={id} className="bg-white p-6 rounded-[3rem] border border-slate-100 shadow-xl space-y-4 group">
                  <div className="aspect-video bg-slate-100 rounded-[2.5rem] relative overflow-hidden border border-slate-50">
                    {design.bgImage && <img src={design.bgImage} className="absolute inset-0 w-full h-full object-cover opacity-50" />}
                    <div className="absolute inset-0">
                      <DesignerOverlay items={design.items} getItemData={getItemData} onRemove={() => {}} alerts={{}} isStatic />
                    </div>
                  </div>
                  <div className="flex justify-between items-end">
                    <div>
                      <h4 className="font-black text-slate-800 uppercase tracking-tight">{design.name}</h4>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{design.items.length} Structural Elements</p>
                    </div>
                    <button onClick={() => loadDesign(design)} className="bg-slate-900 text-white px-5 py-2.5 rounded-xl font-black text-[9px] tracking-widest hover:bg-emerald-600 transition-all uppercase">
                      Activate
                    </button>
                  </div>
                </div>
              );
            })}
            {compareList.length === 0 && (
              <div className="col-span-full py-32 bg-white rounded-[4rem] border-4 border-dashed border-slate-100 flex flex-col items-center justify-center text-slate-300">
                <i className="fas fa-layer-group text-6xl mb-4 opacity-20" />
                <p className="font-black uppercase tracking-widest text-sm">Select variations from the archive to compare</p>
              </div>
            )}
          </div>
        </div>
      ) : (
        /* Primary Workspace Grid */
        <div className="grid lg:grid-cols-4 gap-8 animate-in fade-in duration-500">
          <div className="lg:col-span-3 relative h-[70vh] rounded-[4rem] overflow-hidden border-[12px] border-white shadow-2xl bg-slate-100">
            <div ref={containerRef} onClick={addItem} className="w-full h-full relative cursor-crosshair">
              {designMode === 'live' ? (
                <CameraView isActive={true} overlayContent={<div className="absolute inset-0 pointer-events-none"><DesignerOverlay items={items} getItemData={getItemData} onRemove={(id) => setItems(prev => prev.filter(i => i.instanceId !== id))} alerts={proximityAlerts} /></div>} />
              ) : (
                <div className="w-full h-full flex items-center justify-center bg-slate-200/50 relative">
                  {uploadedImage && <img src={uploadedImage} className="w-full h-full object-cover" />}
                  {!uploadedImage && <div className="text-center opacity-30"><i className="fas fa-camera text-4xl mb-4" /><p className="font-black text-xs uppercase tracking-widest">Awaiting Site Image</p></div>}
                  <div className="absolute inset-0 pointer-events-none"><DesignerOverlay items={items} getItemData={getItemData} onRemove={(id) => setItems(prev => prev.filter(i => i.instanceId !== id))} alerts={proximityAlerts} /></div>
                </div>
              )}
            </div>

            {/* AI Overlay HUD */}
            <div className="absolute top-8 right-8 pointer-events-none max-w-xs">
               <div className={`glass-card p-6 rounded-[2.5rem] border shadow-2xl transition-all ${Object.keys(proximityAlerts).length > 0 ? 'border-red-500/50 bg-red-50/10' : 'border-white/40'}`}>
                  <div className="flex items-center gap-2 mb-2">
                    <div className={`w-2 h-2 rounded-full animate-pulse ${Object.keys(proximityAlerts).length > 0 ? 'bg-red-500' : 'bg-emerald-500'}`} />
                    <p className="text-[9px] font-black uppercase tracking-widest text-slate-700">Spatial Intelligence</p>
                  </div>
                  <p className="text-xs font-bold text-slate-800 leading-tight italic">"{aiSuggestions}"</p>
               </div>
            </div>

            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-slate-900/90 backdrop-blur-xl p-2 rounded-[2.5rem] shadow-2xl">
              {[
                { id: 'plants', icon: 'fa-leaf', label: 'Flora' },
                { id: 'objects', icon: 'fa-chair', label: 'Artifacts' },
                { id: 'surfaces', icon: 'fa-mountain', label: 'Surfaces' }
              ].map(cat => (
                <button key={cat.id} onClick={() => setActiveCategory(cat.id as Category)} className={`px-6 py-3 rounded-full font-black text-[9px] tracking-widest uppercase transition-all flex items-center gap-2 ${activeCategory === cat.id ? 'bg-emerald-500 text-white' : 'text-slate-400 hover:text-white'}`}>
                  <i className={`fas ${cat.icon}`} /> {cat.label}
                </button>
              ))}
            </div>
          </div>

          {/* Asset and Archive Sidebar */}
          <div className="space-y-6 h-[70vh] flex flex-col">
            <div className="bg-white p-6 rounded-[3rem] border border-slate-100 shadow-sm flex-1 overflow-hidden flex flex-col">
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Asset Palette</h4>
              <div className="flex-1 overflow-y-auto pr-2 space-y-3 no-scrollbar">
                {currentPalette.map((p: any) => (
                  <div key={p.id} className={`flex items-center gap-4 p-3 rounded-2xl border-2 transition-all ${selectedItemId === p.id ? 'bg-emerald-50 border-emerald-500' : 'border-transparent bg-slate-50 hover:bg-slate-100'}`}>
                    <button onClick={() => setSelectedItemId(p.id)} className="flex-1 flex items-center gap-3 text-left">
                      <img src={p.imageUrl} className="w-10 h-10 object-contain rounded-lg" />
                      <div className="truncate">
                        <p className="text-[10px] font-black uppercase leading-none mb-1">{p.name}</p>
                        <p className="text-[8px] font-bold text-slate-400 uppercase tracking-tighter">{p.category || 'Environmental'}</p>
                      </div>
                    </button>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-slate-900 p-8 rounded-[3.5rem] shadow-2xl text-white">
               <div className="flex justify-between items-center mb-6">
                  <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-500">History & Contrast</h4>
                  <span className="text-[9px] font-black bg-white/10 px-2 py-0.5 rounded uppercase">Archive</span>
               </div>
               <div className="space-y-3 max-h-56 overflow-y-auto no-scrollbar">
                  {savedDesigns.map(d => (
                    <div key={d.id} className="flex items-center gap-2 group">
                      <button 
                        onClick={() => toggleCompare(d.id)}
                        className={`w-8 h-8 rounded-xl flex items-center justify-center transition-all ${compareList.includes(d.id) ? 'bg-emerald-500 text-white' : 'bg-white/5 text-white/30 hover:bg-white/10'}`}
                      >
                        <i className={`fas ${compareList.includes(d.id) ? 'fa-check' : 'fa-plus'} text-[10px]`} />
                      </button>
                      <button 
                        onClick={() => loadDesign(d)}
                        className="flex-1 flex items-center justify-between p-4 bg-white/5 rounded-2xl hover:bg-white/10 transition-all border border-transparent hover:border-white/5"
                      >
                        <div className="flex flex-col items-start truncate pr-2">
                          <span className="text-[11px] font-black truncate uppercase">{d.name}</span>
                          <span className="text-[8px] text-slate-500 font-bold uppercase">{new Date(d.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                        </div>
                        <i className="fas fa-chevron-right text-[8px] opacity-20" />
                      </button>
                    </div>
                  ))}
                  {savedDesigns.length === 0 && (
                    <div className="text-center py-8 opacity-20">
                      <p className="text-[10px] font-black uppercase">No saved revisions</p>
                    </div>
                  )}
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const DesignerOverlay = ({ items, getItemData, onRemove, alerts, isStatic = false }: any) => (
  <>
    {items.map((item: LandscapeItem) => {
      const data = getItemData(item.itemId);
      const isSurface = item.itemId.startsWith('s');
      return (
        <div
          key={item.instanceId}
          className={`absolute pointer-events-auto group animate-in zoom-in-75 duration-300 ${isStatic ? 'scale-[0.8]' : ''}`}
          style={{
            left: `${item.x}%`,
            top: `${item.y}%`,
            transform: `translate(-50%, -100%) scale(${item.scale})`,
            zIndex: isSurface ? 1 : Math.floor(item.y)
          }}
        >
          <div className="relative">
            {alerts[item.instanceId] && <div className="absolute inset-0 -m-4 border-2 border-red-500/30 rounded-full animate-pulse blur-md" />}
            <img 
              src={data?.imageUrl} 
              className={`${isSurface ? 'w-80 h-60 rounded-[3rem] object-cover mix-blend-multiply opacity-80' : item.type === 'tool' ? 'w-32 h-32 object-contain' : 'w-56 h-72 object-contain'} drop-shadow-2xl`}
              style={{ filter: `brightness(1.05) contrast(${isSurface ? 0.8 : 1.1})` }}
            />
            {!isSurface && <div className="absolute -bottom-4 left-1/2 -translate-x-1/2 w-3/4 h-4 bg-black/30 blur-2xl rounded-full scale-y-[0.25] -z-10" />}
          </div>
          {!isStatic && (
            <div className="absolute -top-12 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 flex gap-2 bg-slate-900 p-2 rounded-xl transition-all border border-white/10 shadow-2xl">
              <button onClick={(e) => { e.stopPropagation(); onRemove(item.instanceId); }} className="text-red-400 px-3 py-1 hover:text-red-500 text-[10px] font-black uppercase">Remove</button>
            </div>
          )}
        </div>
      );
    })}
  </>
);

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { CameraView } from './CameraView';
import { GARDEN_TOOLS } from '../constants';
import { LandscapeItem, Plant, Tool } from '../types';

type DesignMode = 'static' | 'live';
type Category = 'plants' | 'objects' | 'surfaces';

interface SavedDesign {
  id: string;
  name: string;
  items: LandscapeItem[];
  bgImage?: string;
  timestamp: number;
}

interface LandscapeDesignerProps {
  initialItems?: LandscapeItem[];
  onItemsChange?: (items: LandscapeItem[]) => void;
  availablePlants: Plant[];
}

export const LandscapeDesigner: React.FC<LandscapeDesignerProps> = ({ 
  initialItems = [], 
  onItemsChange,
  availablePlants
}) => {
  const [items, setItems] = useState<LandscapeItem[]>(initialItems);
  const [history, setHistory] = useState<LandscapeItem[][]>([]);
  const [designMode, setDesignMode] = useState<DesignMode>('static');
  const [activeCategory, setActiveCategory] = useState<Category>('plants');
  const [selectedItemId, setSelectedItemId] = useState<string>(availablePlants[0]?.id || '');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [savedDesigns, setSavedDesigns] = useState<SavedDesign[]>([]);
  const [currentDesignName, setCurrentDesignName] = useState('Garden Concept Alpha');
  const [compareList, setCompareList] = useState<string[]>([]);
  const [isComparing, setIsComparing] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    onItemsChange?.(items);
  }, [items]);

  useEffect(() => {
    if (initialItems.length !== items.length) {
      setItems(initialItems);
    }
  }, [initialItems]);

  const SURFACE_ASSETS = [
    { id: 's1', name: 'Premium Turf', imageUrl: 'https://images.unsplash.com/photo-1533460004989-cef01064af7c?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's2', name: 'Gravel Path', imageUrl: 'https://images.unsplash.com/photo-1508182314998-3bd49473002f?auto=format&fit=crop&w=400', type: 'surface' },
    { id: 's3', name: 'Paved Walkway', imageUrl: 'https://images.unsplash.com/photo-1590059392253-df2676f4e183?auto=format&fit=crop&w=400', type: 'surface' }
  ];

  const currentPalette = useMemo(() => {
    if (activeCategory === 'plants') return availablePlants;
    if (activeCategory === 'objects') return GARDEN_TOOLS;
    return SURFACE_ASSETS;
  }, [activeCategory, availablePlants]);

  const getItemData = (itemId: string) => {
    return [...availablePlants, ...GARDEN_TOOLS, ...SURFACE_ASSETS].find(x => x.id === itemId);
  };

  const proximityAlerts = useMemo(() => {
    const alerts: Record<string, boolean> = {};
    items.forEach((item, i) => {
      items.forEach((other, j) => {
        if (i === j) return;
        const dx = item.x - other.x;
        const dy = item.y - other.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        const itemData = getItemData(item.itemId);
        const category = (itemData as Plant)?.category || (itemData as Tool)?.category;
        const threshold = category === 'Tree' ? 14 : 8;

        if (distance < threshold) {
          alerts[item.instanceId] = true;
          alerts[other.instanceId] = true;
        }
      });
    });
    return alerts;
  }, [items, availablePlants]);

  const aiSuggestions = useMemo(() => {
    const itemCount = items.length;
    const overcrowded = Object.values(proximityAlerts).filter(v => v).length;
    const hasObjects = items.some(i => i.type === 'tool');

    if (overcrowded > 0) return "PROXIMITY ALERT: Some assets are clipping. Re-position benches or larger plants for better circulation.";
    if (itemCount === 0) return "Your canvas is empty. Start with hardscaping (benches/paths) or a focal tree.";
    if (!hasObjects && itemCount > 2) return "Aesthetic Tip: Add a Stone Fountain or Bench to create a human-centered focal point.";
    return "Composition Harmony: High. The balance between flora and artifacts is currently optimal.";
  }, [items, proximityAlerts]);

  const addItem = (e: React.MouseEvent<HTMLDivElement>) => {
    if (designMode === 'static' && !uploadedImage && !e.shiftKey) return;
    if (!selectedItemId) return;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const newItem: LandscapeItem = {
      instanceId: Math.random().toString(36).substr(2, 9),
      itemId: selectedItemId,
      type: activeCategory === 'plants' ? 'plant' : 'tool',
      x, y, rotation: 0, scale: activeCategory === 'surfaces' ? 2 : (activeCategory === 'objects' ? 0.8 : 1)
    };

    setHistory([...history, items]);
    setItems([...items, newItem]);
  };

  const saveDesign = () => {
    const name = prompt("Enter a name for this variation:", currentDesignName) || `Variation ${savedDesigns.length + 1}`;
    const newDesign: SavedDesign = {
      id: Date.now().toString(),
      name,
      items: [...items],
      bgImage: uploadedImage || undefined,
      timestamp: Date.now()
    };
    setSavedDesigns(prev => [newDesign, ...prev]);
    setCurrentDesignName(name);
  };

  const loadDesign = (design: SavedDesign) => {
    setHistory([...history, items]);
    setItems(design.items);
    if (design.bgImage) {
      setUploadedImage(design.bgImage);
      setDesignMode('static');
    }
    setCurrentDesignName(design.name);
    setIsComparing(false);
  };

  const toggleCompare = (id: string) => {
    setCompareList(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id].slice(-4)
    );
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (re) => setUploadedImage(re.target?.result as string);
      reader.readAsDataURL(file);
      setDesignMode('static');
    }
  };

  const startSpatialToolPreview = (toolId: string) => {
    setActiveCategory('objects');
    setSelectedItemId(toolId);
    setDesignMode('live');
  };

  return (
    <div className="max-w-[1600px] mx-auto space-y-6 pb-12 animate-in fade-in duration-1000">
      <div className="flex flex-col md:flex-row justify-between items-center gap-6 bg-white p-6 rounded-[3rem] shadow-xl border border-slate-100">
        <div className="flex items-center gap-6">
          <div className="flex bg-slate-100 p-1.5 rounded-[2rem]">
            <button onClick={() => setDesignMode('static')} className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all ${designMode === 'static' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400'}`}>BLUEPRINT</button>
            <button onClick={() => setDesignMode('live')} className={`px-8 py-3 rounded-[1.5rem] font-black text-[10px] tracking-widest transition-all ${designMode === 'live' ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400'}`}>LIVE AR</button>
          </div>

          <div className="flex gap-2">
            <button onClick={() => history.length > 0 && setItems(history[history.length-1])} disabled={history.length === 0} className="w-10 h-10 bg-slate-100 text-slate-600 rounded-xl disabled:opacity-30 flex items-center justify-center transition-all"><i className="fas fa-undo" /></button>
            <button onClick={() => setIsComparing(!isComparing)} className={`px-6 py-3 rounded-xl font-black text-[9px] tracking-widest uppercase transition-all flex items-center gap-2 ${isComparing ? 'bg-emerald-600 text-white shadow-lg' : 'bg-slate-100 text-slate-600'}`}>
              <i className="fas fa-columns" /> Compare {compareList.length > 0 && `(${compareList.length})`}
            </button>
          </div>
        </div>

        <div className="flex gap-3">
          <button onClick={() => fileInputRef.current?.click()} className="bg-slate-100 text-slate-600 px-6 py-3 rounded-2xl font-black text-[10px] tracking-widest uppercase">Upload Site</button>
          <button onClick={saveDesign} className="bg-emerald-600 text-white px-8 py-3 rounded-2xl font-black text-[10px] tracking-widest uppercase shadow-lg">Save Version</button>
          <input ref={fileInputRef} type="file" hidden accept="image/*" onChange={handleFileUpload} />
        </div>
      </div>

      {isComparing ? (
        <div className="animate-in zoom-in-95 duration-500">
          <div className="flex justify-between items-center mb-10">
            <div>
              <h2 className="text-4xl font-black text-slate-800 tracking-tighter">Design Contrast Board</h2>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Select and compare your saved architectural concepts</p>
            </div>
            <button onClick={() => setIsComparing(false)} className="bg-slate-900 text-white px-8 py-3 rounded-2xl font-black text-[10px] tracking-widest uppercase hover:bg-emerald-600 transition-all shadow-xl">
              <i className="fas fa-arrow-left mr-2" /> Exit Comparison
            </button>
          </div>

          <div className={`grid gap-8 ${compareList.length >= 3 ? 'grid-cols-3' : compareList.length === 2 ? 'grid-cols-2' : 'grid-cols-1'}`}>
            {compareList.map(id => {
              const design = savedDesigns.find(d => d.id === id);
              if (!design) return null;
              return (
                <div key={id} className="bg-white p-8 rounded-[4rem] border border-slate-100 shadow-2xl space-y-6 group hover:-translate-y-2 transition-transform duration-500">
                  <div className="aspect-[16/10] bg-slate-50 rounded-[3rem] relative overflow-hidden border border-slate-100 shadow-inner">
                    {design.bgImage && <img src={design.bgImage} className="absolute inset-0 w-full h-full object-cover opacity-60" />}
                    <div className="absolute inset-0">
                      <DesignerOverlay items={design.items} getItemData={getItemData} onRemove={() => {}} alerts={{}} isStatic />
                    </div>
                  </div>
                  <div className="flex justify-between items-center px-2">
                    <div>
                      <h4 className="font-black text-xl text-slate-800 tracking-tight">{design.name}</h4>
                      <div className="flex gap-2 mt-1">
                        <span className="text-[9px] font-black bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded uppercase">{design.items.filter(i => i.type === 'plant').length} Flora</span>
                        <span className="text-[9px] font-black bg-blue-100 text-blue-700 px-2 py-0.5 rounded uppercase">{design.items.filter(i => i.type === 'tool').length} Objects</span>
                      </div>
                    </div>
                    <button onClick={() => loadDesign(design)} className="bg-emerald-50 text-emerald-600 px-6 py-3 rounded-2xl font-black text-[10px] tracking-widest hover:bg-emerald-500 hover:text-white transition-all uppercase shadow-sm">
                      Activate
                    </button>
                  </div>
                </div>
              );
            })}
            {compareList.length === 0 && (
              <div className="col-span-full py-48 bg-white rounded-[5rem] border-4 border-dashed border-slate-100 flex flex-col items-center justify-center text-slate-300">
                <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mb-6">
                   <i className="fas fa-layer-group text-4xl opacity-30" />
                </div>
                <p className="font-black uppercase tracking-widest text-sm">Select items from the archive to compare</p>
                <p className="text-[10px] font-bold text-slate-400 mt-2 uppercase">Use the plus icons in the side panel</p>
              </div>
            )}
          </div>
        </div>
      ) : (
        <div className="grid lg:grid-cols-4 gap-8 animate-in fade-in duration-500">
          <div className="lg:col-span-3 relative h-[70vh] rounded-[4rem] overflow-hidden border-[12px] border-white shadow-2xl bg-slate-100">
            <div ref={containerRef} onClick={addItem} className="w-full h-full relative cursor-crosshair">
              {designMode === 'live' ? (
                <CameraView isActive={true} overlayContent={<div className="absolute inset-0 pointer-events-none"><DesignerOverlay items={items} getItemData={getItemData} onRemove={(id) => setItems(prev => prev.filter(i => i.instanceId !== id))} alerts={proximityAlerts} /></div>} />
              ) : (
                <div className="w-full h-full flex items-center justify-center bg-slate-200/50 relative">
                  {uploadedImage && <img src={uploadedImage} className="w-full h-full object-cover" />}
                  {!uploadedImage && <div className="text-center opacity-30"><i className="fas fa-camera text-4xl mb-4" /><p className="font-black text-xs uppercase tracking-widest">Awaiting Site Image</p></div>}
                  <div className="absolute inset-0 pointer-events-none"><DesignerOverlay items={items} getItemData={getItemData} onRemove={(id) => setItems(prev => prev.filter(i => i.instanceId !== id))} alerts={proximityAlerts} /></div>
                </div>
              )}
            </div>

            <div className="absolute top-8 right-8 pointer-events-none max-w-xs">
               <div className={`glass-card p-6 rounded-[2.5rem] border shadow-2xl transition-all ${Object.keys(proximityAlerts).length > 0 ? 'border-red-500/50 bg-red-50/10' : 'border-white/40'}`}>
                  <div className="flex items-center gap-2 mb-2">
                    <div className={`w-2 h-2 rounded-full animate-pulse ${Object.keys(proximityAlerts).length > 0 ? 'bg-red-500' : 'bg-emerald-500'}`} />
                    <p className="text-[9px] font-black uppercase tracking-widest text-slate-700">Spatial Intelligence</p>
                  </div>
                  <p className="text-xs font-bold text-slate-800 leading-tight italic">"{aiSuggestions}"</p>
               </div>
            </div>

            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-slate-900/90 backdrop-blur-xl p-2 rounded-[2.5rem] shadow-2xl">
              {[
                { id: 'plants', icon: 'fa-leaf', label: 'Flora' },
                { id: 'objects', icon: 'fa-chair', label: 'Artifacts' },
                { id: 'surfaces', icon: 'fa-mountain', label: 'Surfaces' }
              ].map(cat => (
                <button key={cat.id} onClick={() => setActiveCategory(cat.id as Category)} className={`px-6 py-3 rounded-full font-black text-[9px] tracking-widest uppercase transition-all flex items-center gap-2 ${activeCategory === cat.id ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}>
                  <i className={`fas ${cat.icon}`} /> {cat.label}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-6 h-[70vh] flex flex-col">
            <div className="bg-white p-6 rounded-[3rem] border border-slate-100 shadow-sm flex-1 overflow-hidden flex flex-col">
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 px-2">Project Assets</h4>
              <div className="flex-1 overflow-y-auto pr-2 space-y-3 no-scrollbar">
                {currentPalette.map((p: any) => (
                  <div key={p.id} className={`flex items-center gap-4 p-3 rounded-2xl border-2 transition-all ${selectedItemId === p.id ? 'bg-emerald-50 border-emerald-500 shadow-sm' : 'border-transparent bg-slate-50 hover:bg-slate-100'}`}>
                    <button onClick={() => setSelectedItemId(p.id)} className="flex-1 flex items-center gap-3 text-left">
                      <div className="w-10 h-10 bg-white rounded-lg p-1 flex items-center justify-center">
                        <img src={p.imageUrl} className="w-full h-full object-contain" />
                      </div>
                      <div className="truncate">
                        <p className="text-[10px] font-black uppercase leading-none mb-1">{p.name}</p>
                        <p className="text-[8px] font-bold text-slate-400 uppercase tracking-tighter">{p.category || 'Asset'}</p>
                      </div>
                    </button>
                    {activeCategory === 'objects' && (
                      <button onClick={() => startSpatialToolPreview(p.id)} className="w-8 h-8 bg-emerald-100 text-emerald-600 rounded-lg hover:bg-emerald-500 hover:text-white transition-all shadow-sm">
                        <i className="fas fa-eye text-[10px]" />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-slate-900 p-8 rounded-[3.5rem] shadow-2xl text-white">
               <div className="flex justify-between items-center mb-6">
                  <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-500">History & Contrast</h4>
                  <span className="text-[9px] font-black bg-white/10 px-2 py-0.5 rounded uppercase">Archive</span>
               </div>
               <div className="space-y-3 max-h-56 overflow-y-auto no-scrollbar">
                  {savedDesigns.map(d => (
                    <div key={d.id} className="flex items-center gap-2 group">
                      <button 
                        onClick={() => toggleCompare(d.id)}
                        className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${compareList.includes(d.id) ? 'bg-emerald-500 text-white' : 'bg-white/5 text-white/30 hover:bg-white/10'}`}
                      >
                        <i className={`fas ${compareList.includes(d.id) ? 'fa-check' : 'fa-plus'} text-[10px]`} />
                      </button>
                      <button 
                        onClick={() => loadDesign(d)}
                        className="flex-1 flex items-center justify-between p-4 bg-white/5 rounded-2xl hover:bg-white/10 transition-all border border-transparent hover:border-white/5"
                      >
                        <div className="flex flex-col items-start truncate pr-2">
                          <span className="text-[11px] font-black truncate uppercase tracking-tight">{d.name}</span>
                          <span className="text-[8px] text-slate-500 font-bold uppercase">{new Date(d.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                        </div>
                        <i className="fas fa-chevron-right text-[8px] opacity-20" />
                      </button>
                    </div>
                  ))}
                  {savedDesigns.length === 0 && (
                    <div className="text-center py-8 opacity-20 border-2 border-dashed border-white/5 rounded-3xl">
                      <p className="text-[10px] font-black uppercase tracking-widest">Empty Workspace</p>
                    </div>
                  )}
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

