              { id: 'landscape', icon: 'fa-pencil-ruler', label: 'DESIGN' },
              { id: 'doctor', icon: 'fa-stethoscope', label: 'DOCTOR' },
              { id: 'wishlist', icon: 'fa-heart', label: 'SAVED' },
              { id: 'history', icon: 'fa-truck', label: 'ORDERS' }
